/* Auto-generated session data for search */
window.FABCON_SESSIONS = [{"t": "Modern Data Warehousing in Microsoft Fabric", "d": "2026-03-16", "s": "09:00 AM", "e": "05:00 PM", "tr": "Data Warehousing", "ty": "Session", "l": "300", "sp": ["Kristyna Ferris", "Chris Hyde"], "desc": "Learn how to design and manage data warehouses in Microsoft Fabric by exploring proven patterns, practical techniques, and common pitfalls to avoid. Topics include dimensional modeling, data warehousing fundamentals, ingestion strategies, medallion architecture, change detection, lifecycle management with CI/CD, monitoring, administration, and migrations.", "u": "https://fabriccon.com/program/agenda?session=1020569", "tags": ["Data Warehousing"]}, {"t": "Getting Started with Microsoft Fabric and Power BI: A Hands-On Workshop", "d": "2026-03-16", "s": "09:00 AM", "e": "05:00 PM", "tr": "Data Engineering, Power BI", "ty": "Workshop", "l": "100", "sp": ["Stephanie Bruno", "Santhana Lakshmi Ponnurasan"], "desc": "New to Fabric or Power BI? This workshop is the perfect place to start, giving you an end-to-end intro to Fabric and Power BI and equipping you with the skills and confidence to dive deeper into the world of modern analytics.\n\nWe’ll start with Fabric in the morning, building out an end-to-end solution, then on Power BI in the afternoon. \n\nThrough guided exercises led by experts, you'll gain knowledge you can take back to your own projects, and you'll be set up for a successful conference! \n\n*Please note that this workshop is hands-on and requires attendees to bring a laptop to participate.", "u": "https://fabriccon.com/program/agenda?session=1042946", "tags": ["Power BI", "Data Engineering"]}, {"t": "Chat with Your Data: Discover the Future of Data Insights with Power BI Copilot", "d": "2026-03-16", "s": "09:00 AM", "e": "05:00 PM", "tr": "Power BI", "ty": "Session", "l": "200", "sp": ["Lada Hill", "Lauren Faber", "Stephen Godderidge"], "desc": "In this hands-on session, we'll show you how to leverage Power BI and Microsoft Fabric's Copilot AI features to chat with your data. Learn how to prepare data for end-users with AI features like Instructions and Verified Answers. You'll get practical experience with the standalone Copilot interface, exploring its capabilities to deliver insights. This session will empower you to transform how your organization interacts with data for smarter decision-making and deeper insights.\n\n*Please note that this workshop is hands-on and requires attendees to bring a laptop to participate.", "u": "https://fabriccon.com/program/agenda?session=1046381", "tags": ["Power BI"]}, {"t": "Design a Well-Architected Fabric Solution: A Medallion First Approach", "d": "2026-03-16", "s": "09:00 AM", "e": "05:00 PM", "tr": "Data Engineering, Data Integration", "ty": "Session", "l": "200", "sp": ["Reid Havens", "Steve Campbell"], "desc": "Solid data architecture is key for a scalable and maintainable pipeline, but can be difficult to implement.\nThis session is for those familiar with Power BI or new data engineers, providing a step-by-step guide to Bronze, Silver, and Gold layers.\nUsers will gain an overview of Medallion Architecture, Warehouses and Lakehouses, Delta and Parquet, GIT integration, monitoring, and compare available Fabric tools. This is a hands on, lab filled session. Python or SQL is a bonus but not required.\n\n*Please note that this workshop is hands-on and requires attendees to bring a laptop to participate.", "u": "https://fabriccon.com/program/agenda?session=1047353", "tags": ["Data Engineering", "Data Integration"]}, {"t": "A practical guide to building and deploying Fabric Data Agents for deeper insights", "d": "2026-03-16", "s": "09:00 AM", "e": "05:00 PM", "tr": "Data Science", "ty": "Session", "l": "200", "sp": ["Shreyas Canchi Radhakrishna", "Mayur Jain", "Scott Votaw"], "desc": "AI agents are becoming integral to business workflows, enabling users of all technical levels to explore and understand data more intuitively, and Microsoft Fabric’s Data Agents are at the forefront of this transformation.\n\nIn this tutorial, you’ll dive into how Fabric empowers you to build, configure, and optimize a Data Agent. You’ll learn best practices for curating high-quality data inputs, configuring agents, and leveraging rich features to turn raw data into actionable insights. \n\n*Please note that this workshop is hands-on and requires attendees to bring a laptop to participate.", "u": "https://fabriccon.com/program/agenda?session=1042362", "tags": ["Data Science"]}, {"t": "Hands-On Workshop: Data Science & Machine Learning with Microsoft Fabric", "d": "2026-03-16", "s": "09:00 AM", "e": "05:00 PM", "tr": "Data Science, Microsoft Foundry", "ty": "Workshop", "l": "300", "sp": ["Prashant G Bhoyar"], "desc": "Explore Microsoft Fabric’s integrated Data Science experience across ideation, preprocessing, modeling, & deployment. Learn how to ingest and prepare data via OneLake and Lakehouse, leverage Notebooks, Data Wrangler, Spark, SynapseML, MLflow for experimentation, & operationalize predictions with batch scoring and Power BI direct integration. Also, learn to build generative AI Q&A systems using Fabric Data Agents.. Participants will receive access to Microsoft Fabric & Azure to perform the labs.\n\n*Please note that this workshop is hands-on and requires attendees to bring a laptop to participate.", "u": "https://fabriccon.com/program/agenda?session=1032680", "tags": ["Data Science", "Microsoft Foundry"]}, {"t": "Real-Time Intelligence Masterclass with Microsoft Fabric", "d": "2026-03-16", "s": "09:00 AM", "e": "05:00 PM", "tr": "Real-Time Intelligence", "ty": "Masterclass", "l": "300", "sp": ["Frank Geisler", "Johan Ludvig Brattås"], "desc": "Today’s organizations need real-time insights. This hands-on workshop guides data pros in building event-driven solutions with Microsoft Fabric. In a full-day lab, you’ll use Real-Time Intelligence (Eventstream, Eventhouse, Lakehouse, Dashboards, Activator, Agents, Digital Twin Builder) to create end-to-end architectures. Learn CDC streams, streaming data, schema drift, real-time dashboards, alerts, agents, ML scoring, plus cost & performance insights.\n\n*Please note that this workshop is hands-on and requires attendees to bring a laptop to participate.", "u": "https://fabriccon.com/program/agenda?session=1040669", "tags": ["Real-Time Intelligence"]}, {"t": "Hands-On Fabric Security: Protecting Data, Access, and Compliance", "d": "2026-03-16", "s": "09:00 AM", "e": "05:00 PM", "tr": "Admin & Governance, Microsoft Purview", "ty": "Workshop", "l": "300", "sp": ["Vengatesh Parasuraman", "Amanjeet Singh"], "desc": "This hands-on workshop is designed for data engineers, architects, and security professionals. With a blend of demonstrations, hands-on labs, and real-world scenarios, you’ll leave with a clear understanding of Fabric security. By the end of the session, you will: Learn to protect network traffic in and out of Fabric; Manage user access with OneLake security; Apply compliance best practices with built-in governance and auditing tools by leveraging Microsoft Purview and Sensitivity Labels.\n\n*Please note that this workshop is hands-on and requires attendees to bring a laptop to participate.", "u": "https://fabriccon.com/program/agenda?session=1046169", "tags": ["Admin & Governance", "Microsoft Purview"]}, {"t": "Mastering Data Factory in Microsoft Fabric: From Security to Operationalization", "d": "2026-03-16", "s": "09:00 AM", "e": "05:00 PM", "tr": "Data Integration", "ty": "Session", "l": "100", "sp": ["Abhishek Narain", "Michaela Isaacs"], "desc": "Fabric Data Factory enables organizations unify their data estate with OneLake. Security is paramount. You will learn how to secure your data ingestion, transformation using workspace identity auth and Azure Key Vault integration, implement network isolation (Private Link and VNet gateway) for accessing data behind firewall. Operationalization is another important aspect. You will learn to operationalize pipeline, dataflow gen2 with variable library, build metadata driven pipelines and more.\n\n*Please note that this workshop is hands-on and requires attendees to bring a laptop to participate.", "u": "https://fabriccon.com/program/agenda?session=1046086", "tags": ["Data Integration"]}, {"t": "Mastering SQL Server Performance & Optimization Strategies", "d": "2026-03-16", "s": "09:00 AM", "e": "05:00 PM", "tr": "Azure SQL, SQLCON", "ty": "Session", "l": "100", "sp": ["John Morehouse", "Monica Morehouse (Rathbun)"], "desc": "Everyone wants their database to go faster, whether it's shaving hours off your ETL process, taking minutes off the runtime for reports, or trimming milliseconds off a critical OLTP query. Every database professional must know where to look and how to tune, whether you have one SQL environment or thousands. \n \nIn this full-day session, you'll learn how to take your performance tuning skills to the next level.", "u": "https://fabriccon.com/program/agenda?session=1046487", "tags": ["SQLCON", "Azure SQL"]}, {"t": "SQL Server 2025 Deep Dive: Essential Innovations for DBAs and Database Developers", "d": "2026-03-16", "s": "09:00 AM", "e": "05:00 PM", "tr": "SQL Server, SQLCON", "ty": "Session", "l": "300", "sp": ["Joey Dantoni", "Matt Gordon"], "desc": "SQL Server 2025 is the AI database for enterprises. But there are more new things than just AI—in this demo filled, full-day workshop, you will learn about:\n•\tEngine improvements that make everything just run faster\n•\tHow SQL Server 2025 helps you operate more securely\n•\tFurther enhancements to high availability \n•\tBuilding event-driven architectures with change event streaming\n\nMaster the benefits of the latest release of SQL Server and how to deploy it in your organization.", "u": "https://fabriccon.com/program/agenda?session=1066723", "tags": ["SQL Server", "SQLCON"]}, {"t": "Power BI Mastery: End-to-End Analytics for Pro Developers", "d": "2026-03-17", "s": "09:00 AM", "e": "05:00 PM", "tr": "Power BI", "ty": "Session", "l": "300", "sp": ["Sara Lammini Rodriguez", "Monica Calleja", "Rui Romano"], "desc": "Join this hands-on workshop for Power BI Pro Developers and data practitioners. Gain practical experience across the full development lifecycle using tools like PBIP, TMDL, and PBIR. Learn how Pro Developer features integrate with code-first and AI-powered experiences to streamline workflows, enforce best practices, and speed up delivery. Walk away ready to deliver enterprise-grade Power BI solutions.\n\n*Please note that this workshop is hands-on and requires attendees to bring a laptop to participate.", "u": "https://fabriccon.com/program/agenda?session=1046398", "tags": ["Power BI"]}, {"t": "Architecting Data Warehouse Medallion Architecture: From Ingestion to Security at Lightning Speed", "d": "2026-03-17", "s": "09:00 AM", "e": "05:00 PM", "tr": "Data Warehousing, Admin & Governance", "ty": "Session", "l": "300", "sp": ["Freddie Santos", "Venkata Satya Pradeep Srikakolapu", "Bradley Schacht"], "desc": "Building a high-performing, secure, and future-ready data warehouse requires more than just loading data—it demands a well-structured architecture that balances speed, governance, and scalability. In this workshop, we’ll walk through how to design and implement a medallion architecture (Bronze, Silver, Gold) in Microsoft Fabric, taking you end-to-end from raw data ingestion to refined, governed, and consumable insights.\n\n*Please note that this workshop is hands-on and requires attendees to bring a laptop to participate.", "u": "https://fabriccon.com/program/agenda?session=1037519", "tags": ["Admin & Governance", "Data Warehousing"]}, {"t": "Build AI-Ready applications with SQL Database in Microsoft Fabric", "d": "2026-03-17", "s": "09:00 AM", "e": "05:00 PM", "tr": "SQL in Fabric, SQLCON", "ty": "Session", "l": "200", "sp": ["Anna Hoffman", "Idris Motiwala", "Sukhwant Kaur"], "desc": "Join us for a hands-on workshop to design, deploy, and optimize AI-powered apps using SQL Database in Microsoft Fabric. Learn to use Copilot for RAG patterns, build write-back Power BI reports, transform data with Spark/Python, and curate medallion architectures. You'll implement enterprise-grade security, monitor workloads, and manage source control. Leave with a working solution, practical skills, and insights to accelerate AI-to-BI innovation.\n\n*Please note that this workshop is hands-on and requires attendees to bring a laptop to participate.", "u": "https://fabriccon.com/program/agenda?session=1038074", "tags": ["SQLCON", "SQL in Fabric"]}, {"t": "Mastering Fabric Capacities: Governance, Optimization & Real-Time Insights", "d": "2026-03-17", "s": "09:00 AM", "e": "05:00 PM", "tr": "Admin & Governance", "ty": "Session", "l": "300", "sp": ["Sanjay Raut", "Pat Mahoney"], "desc": "This workshop equips Capacity and Fabric Administrators with practical skills to manage and govern Fabric Capacities.\nAgenda includes:\n*  Licensing models, Capacity Units, bursting, throttling\n*  Roles, permissions, metrics app, labs\n*  RTH events, throttling recovery, surge protection\n*  Governance strategies and capacity planning\nLearn to provision, monitor, and govern Fabric Capacities with hands-on labs. Ideal for admins seeking to optimize performance and scale responsibly.\n\n*Please note that this workshop is hands-on and requires attendees to bring a laptop to participate.", "u": "https://fabriccon.com/program/agenda?session=1041034", "tags": ["Admin & Governance"]}, {"t": "Mastering Dataflow Gen2 for ETL in Microsoft Fabric", "d": "2026-03-17", "s": "09:00 AM", "e": "05:00 PM", "tr": "Data Integration, Power BI", "ty": "Session", "l": "300", "sp": ["Reza Rad"], "desc": "Dataflow Gen2 is the core data transformation tool in Microsoft Fabric, powered by the Power Query engine. In this hands-on workshop, attendees will learn to build scalable solutions by extracting data from diverse sources, implementing data transformation and ETL patterns, optimizing performance, leveraging query folding, using parameters and custom functions, utilizing M scripting, applying best practices, debugging techniques, and integrating with pipelines for end-to-end data integration.\n\n*Please note that this workshop is hands-on and requires attendees to bring a laptop to participate.", "u": "https://fabriccon.com/program/agenda?session=1045906", "tags": ["Power BI", "Data Integration"]}, {"t": "Engineering Excellence with Fabric Spark - Test, Model, Predict, and Scale", "d": "2026-03-17", "s": "09:00 AM", "e": "05:00 PM", "tr": "Data Engineering", "ty": "Session", "l": "300", "sp": ["Raki Rahman", "Miles Cole", "Anu Venkataraman"], "desc": "Join this hands-on workshop to learn how a Microsoft engineering team uses Fabric Spark to tackle real-world data engineering challenges. Learn to build scalable data pipelines with Spark Structured Streaming, ML augmentation, and STAR Schema-based dimensional modeling. The workshop covers an end-to-end medallion architecture, leaving you with reusable code assets, patterns, and tips, to accelerate building your own enterprise-ready data pipelines that can be debugged, deployed, and tested.\n\n*Please note that this workshop is hands-on and requires attendees to bring a laptop to participate.", "u": "https://fabriccon.com/program/agenda?session=1046073", "tags": ["Data Engineering"]}, {"t": "Beyond Buzzwords: Hands-On Agentic Patterns for Power BI", "d": "2026-03-17", "s": "09:00 AM", "e": "05:00 PM", "tr": "Developer Experiences, Power BI", "ty": "Workshop", "l": "300", "sp": ["Mathias Thierbach", "Mike Carlo"], "desc": "This full-day workshop explores agentic development patterns for Power BI projects. You’ll learn how GitHub Copilot and MCP servers can accelerate modeling, reporting, and deployment, while also examining their current limits and best-fit scenarios. Through guided, end-to-end exercises, attendees will gain hands-on experience applying agentic practices to Power BI, leaving with practical insights on where these approaches add value—and where traditional methods still matter.\n\n*Please note that this workshop is hands-on and requires attendees to bring a laptop to participate.", "u": "https://fabriccon.com/program/agenda?session=1044026", "tags": ["Power BI", "Developer Experiences"]}, {"t": "Building your data catalog with Microsoft Purview", "d": "2026-03-17", "s": "09:00 AM", "e": "05:00 PM", "tr": "Admin & Governance, Microsoft Purview", "ty": "Session", "l": "300", "sp": ["Darren Portillo", "Shafiq Mannan", "Sri Kutuva"], "desc": "Join us in a hands-on lab to create your data catalog. This lab will include Data Map, Unified Catalog and a lab for Data Security.\n\nCataloging\n1. Ingesting metadata \n2. Curating and creating business concepts\n\nData Health\n1. Configuring rules, scheduling, profiling and scans\n2. Applying controls and viewing reports\n3. Exporting metadata to Fabric \n\nWorkflows\n1. Customizing access request and curation workflows\n\nData Security:\n1. Applying MIP labels and DLP policies\n2. Setting up IRM and DSPM \n\n*Please note that this workshop is hands-on and requires attendees to bring a laptop to participate.", "u": "https://fabriccon.com/program/agenda?session=1046508", "tags": ["Admin & Governance", "Microsoft Purview"]}, {"t": "Deep dive into CI/CD strategies for Microsoft Fabric using Azure DevOps", "d": "2026-03-17", "s": "09:00 AM", "e": "05:00 PM", "tr": "Developer Experiences", "ty": "Session", "l": "400", "sp": ["Kev Chant", "John Kerski"], "desc": "Take a deep dive into CI/CD strategies for Microsoft Fabric using Azure DevOps. This session explores Git-integrated deployments, Azure Pipelines, variable management and various tooling's. \n\nWe’ll also examine testing approaches and automation design patterns to help you build robust, maintainable deployment workflows tailored to Fabric’s architecture.\n\nBy the end of the workshop you will have the knowledge to deploy with confidence.", "u": "https://fabriccon.com/program/agenda?session=1046490", "tags": ["Developer Experiences"]}, {"t": "Building Scalable Real-Time Solutions using Event-Driven Architectures with Microsoft Fabric", "d": "2026-03-17", "s": "09:00 AM", "e": "05:00 PM", "tr": "Real-Time Intelligence", "ty": "Session", "l": "300", "sp": ["Minni Walia", "Heidi Hasting"], "desc": "In this workshop, participants will build end-to-end solution using Microsoft Fabric’s Real-Time Intelligence and IQ capabilities using: Real-Time Hub, Eventstream, Eventhouse, Lakehouse, Real-Time Dashboards, Power BI, Activator, AI Agents, IQ including: \n\n• Connecting to diverse data sources\n• Developing data transformation and enrichment logic\n• Building real-time operational monitoring dashboards and triggering immediate actions\n• Implementing AI agents and Anomaly Detection\n• Fabric IQ demonstration for building a semantic intelligence layer\n• Learn about event-driven architectures best practices                                                                                                  \n*Please note that this workshop is hands-on and requires attendees to bring a laptop to participate.", "u": "https://fabriccon.com/program/agenda?session=1045346", "tags": ["Real-Time Intelligence"]}, {"t": "From Vectors to Agents: Building AI-Powered Solutions with Microsoft SQL", "d": "2026-03-17", "s": "09:00 AM", "e": "05:00 PM", "tr": "SQL Server, SQLCON", "ty": "Session", "l": "300", "sp": ["Davide Mauri", "Aaron Saidi"], "desc": "Unlock the power of your own data by combining Microsoft SQL (SQL Server 2025, Azure SQL, or SQL Database in Microsoft Fabric) with cutting-edge AI techniques. In this workshop, you’ll learn about embeddings and vector search and why they matter for modern AI applications. We’ll guide you through generating embeddings using similarity search to retrieve the most relevant data.\nWe’ll implement the Retrieval-Augmented Generation (RAG) pattern by calling a Chat model, then explore its limitations.  Evolve into Agentic RAG and create an orchestrator to intelligently choose between running semantic search or writing a SQL query to answer complex requests. Learn to secure data access so that only authorized information is available to AI agents using Row-Level Security.\nBy the end, you’ll have built an end-to-end solution that combines SQL’s reliability with AI’s intelligence and be well prepared for SQL AI Developer certification exam.", "u": "https://fabriccon.com/program/agenda?session=1080345", "tags": ["SQL Server", "SQLCON"]}, {"t": "KEYNOTE: Unifying the Data Estate for the next AI Frontier", "d": "2026-03-18", "s": "08:45 AM", "e": "11:45 AM", "tr": "No Track", "ty": "KEYNOTE", "l": "", "sp": ["Arun Ulag", "Amir Netz", "Shireesh Thota"], "desc": "As organizations race to deploy generative and agentic AI, the biggest challenge they face is not models, it’s their data estate. Join Microsoft engineering leadership to learn how Microsoft’s databases can be unified through Microsoft Fabric and OneLake, creating a single, governed foundation for analytics, AI, and intelligent agents. Discover why this shift represents a fundamental change in how modern data platforms are built, managed, and scaled for the next AI frontier.", "u": "https://fabriccon.com/program/agenda?session=1135450", "tags": ["No Track"]}, {"t": "AI for BI: A Practical Guide to Avoiding Common Pitfalls", "d": "2026-03-18", "s": "12:40 PM", "e": "01:00 PM", "tr": "Power BI", "ty": "Session", "l": "100", "sp": ["Marius Moscovici"], "desc": "Every BI platform now includes AI—from Microsoft Fabric CoPilot to standalone chatbots. Yet without a unified strategy, these tools create fragmented user experiences and governance risks. This session introduces a clear Reference Architecture for implementing AI for BI at scale—helping enterprises eliminate silos, ensure control, and build a sustainable, scalable system.", "u": "https://fabriccon.com/program/agenda?session=1095397", "tags": ["Power BI"]}, {"t": "Vortex: AI-Powered Migration to Power BI / Microsoft Fabric Made Simple", "d": "2026-03-18", "s": "12:40 PM", "e": "01:00 PM", "tr": "Power BI", "ty": "Session", "l": "100", "sp": ["Nathan Hombroek", "Andrew Beier"], "desc": "Legacy platforms create data silos blocking innovation. Manual migrations take 12+ months with 83% failing. See how AI automation transforms this: smart rationalization prioritizes assets, automated conversion handles apps and pipelines, and optimization ensures quality. Watch live demos and hear how one organization migrated an app portfolio in months, unlocking Fabric's modern capabilities.", "u": "https://fabriccon.com/program/agenda?session=1081529", "tags": ["Power BI"]}, {"t": "How to build a 360-degree view of customers, suppliers, or contacts across OneLake", "d": "2026-03-18", "s": "12:40 PM", "e": "01:00 PM", "tr": "Power BI, Data Integration", "ty": "Session", "l": "200", "sp": ["Michael Destein"], "desc": "Learn how to create a 360-degree, contextual view across all your OneLake data in Microsoft Fabric. See how to perform high-quality data matching using Entity Resolution techniques across different entity types, eg. people, businesses and locations. Accurately link data across sources and enrich incomplete data. Break down silos and get your data ready for AI, powering better and faster decisions.", "u": "https://fabriccon.com/program/agenda?session=1079051", "tags": ["Power BI", "Data Integration"]}, {"t": "Brewing Better Decisions for a Dunkin Donuts Franchisee with Microsoft Fabric", "d": "2026-03-18", "s": "01:10 PM", "e": "01:30 PM", "tr": "OneLake, Data Engineering", "ty": "Session", "l": "100", "sp": ["Dennis Carriere", "Darren Goonawardana"], "desc": "Learn how Bluemont Group transformed Data & AI across 100 Dunkin’ locations by replacing a vendor-controlled data warehouse with a modern, fully owned Microsoft Fabric platform. Learn how Collectiv helped them eliminate multi-day data delays, unlock historical insights, and empower managers with real-time, location-level visibility.", "u": "https://fabriccon.com/program/agenda?session=1079741", "tags": ["Data Engineering", "OneLake"]}, {"t": "Automate Decision Workflows in Microsoft Fabric", "d": "2026-03-18", "s": "01:10 PM", "e": "01:30 PM", "tr": "SQL in Fabric, Power BI", "ty": "Session", "l": "200", "sp": ["Kumar Thangamuthu"], "desc": "Organizations must act on data fast—but speed without governance creates risk. SAS® Decision Builder on Microsoft Fabric automates governed decision workflows, uniting business rules, analytics, Python, ML, and compliance in one Fabric-native experience. Deliver AI-powered insights and actions with enterprise-grade transparency and control.", "u": "https://fabriccon.com/program/agenda?session=1100054", "tags": ["Power BI", "SQL in Fabric"]}, {"t": "Agentic way to maximize your Fabric capacity utilization", "d": "2026-03-18", "s": "01:10 PM", "e": "01:30 PM", "tr": "Admin & Governance, Real-Time Intelligence", "ty": "Session", "l": "200", "sp": ["Keshav Polepalle", "Benjamin Ries-Roncalli"], "desc": "Overpaying for Fabric capacity? Discover an agentic workload that continuously right-sizes capacity, detects outlier artifacts, sends intelligent alerts, and surfaces usage trends, transforming capacity management from reactive tuning into a self-optimizing, intelligent system.", "u": "https://fabriccon.com/program/agenda?session=1101247", "tags": ["Admin & Governance", "Real-Time Intelligence"]}, {"t": "CORENOTE: The Roadmap for Microsoft SQL: Ground to Cloud to Fabric", "d": "2026-03-18", "s": "01:45 PM", "e": "02:45 PM", "tr": "Azure SQL, SQLCON, SQL Server", "ty": "CORENOTE", "l": "200", "sp": ["Priya Sathy", "Bob Ward", "Anna Hoffman"], "desc": "Join us for an in-depth session on the future of Microsoft SQL—from on-premises to Azure and into Microsoft Fabric. Discover our unified, AI-ready relational database that powers modernization and next-gen AI apps. See how SQL delivers consistency, performance, and innovation everywhere you need it!", "u": "https://fabriccon.com/program/agenda?session=1071703", "tags": ["SQLCON", "Azure SQL", "SQL Server"]}, {"t": "CORENOTE: Fabric Data Factory: What's New and Roadmap", "d": "2026-03-18", "s": "01:45 PM", "e": "02:45 PM", "tr": "Data Integration", "ty": "CORENOTE", "l": "100", "sp": ["Wee Hyong Tok", "Faisal Mohamood"], "desc": "Are you looking at how you can get started with Fabric Data Factory? In this session, you will learn how Fabric Data Factory is empowering developers to build data integration solutions. This session will get you up to speed with exciting product innovations and Fabric Data Factory roadmap.", "u": "https://fabriccon.com/program/agenda?session=1019145", "tags": ["Data Integration"]}, {"t": "CORENOTE: Maximizing developer experiences in Microsoft Fabric", "d": "2026-03-18", "s": "01:45 PM", "e": "02:45 PM", "tr": "Developer Experiences, Admin & Governance", "ty": "CORENOTE", "l": "200", "sp": ["Kim Manis", "Gerd Saurer", "Miles Cole"], "desc": "Discover the latest advancements in Microsoft Fabric that provide a delightful developer experience. Explore capabilities and best practices for job scheduling, proactive and reactive monitoring, troubleshooting, versioning, and deployments. \n\nLearn how these improvements can help you efficiently deploy, operate, troubleshoot, and optimize jobs within your data solutions.", "u": "https://fabriccon.com/program/agenda?session=1075744", "tags": ["Developer Experiences", "Admin & Governance"]}, {"t": "Designing for the Right User: Why Personas Are the Secret to Better Power BI Reports", "d": "2026-03-18", "s": "01:45 PM", "e": "02:45 PM", "tr": "Power BI", "ty": "Session", "l": "200", "sp": ["Elena Drakulevska"], "desc": "Reports don’t fail because you’re bad at design. They fail because they’re built for the wrong user. Learn how to identify the real “characters” behind your Power BI reports, from the big-picture strategist to the action-taker and the detail-obsessed analyst, and how to tailor layout, detail, and interactions so each user gets what they need to make confident decisions.", "u": "https://fabriccon.com/program/agenda?session=1081465", "tags": ["Power BI"]}, {"t": "CORENOTE: The Future of AI in Microsoft Fabric: Data Agents and Beyond", "d": "2026-03-18", "s": "01:45 PM", "e": "02:45 PM", "tr": "Data Science", "ty": "CORENOTE", "l": "200", "sp": ["Nellie Gustafsson", "Markus Weimer"], "desc": "This session will cover how Fabric brings AI to your data using interoperable Data Agents that work across the AI ecosystem to unlock deeper insights. You’ll also learn how AI-powered data engineering and data science capabilities help teams create intelligent, enterprise-ready solutions.", "u": "https://fabriccon.com/program/agenda?session=1070859", "tags": ["Data Science"]}, {"t": "Azure Cosmos DB as a Time Machine: Event Sourcing for Real-Time Intelligence", "d": "2026-03-18", "s": "01:45 PM", "e": "02:45 PM", "tr": "Cosmos DB, Microsoft Foundry", "ty": "Session", "l": "300", "sp": ["Divakar Kumar"], "desc": "What if your database was a time machine? With Cosmos DB and event sourcing, every change is immutable and replayable. Add agents on the change feed, and events don’t just record history — they detect fraud, flag anomalies, and shape the future in real time.", "u": "https://fabriccon.com/program/agenda?session=1050365", "tags": ["Microsoft Foundry", "Cosmos DB"]}, {"t": "End-to-End Security for Data Warehousing in Microsoft Fabric", "d": "2026-03-18", "s": "01:45 PM", "e": "02:45 PM", "tr": "Data Warehousing, Admin & Governance", "ty": "Session", "l": "300", "sp": ["Shabnam Watson"], "desc": "Learn how to secure Microsoft Fabric Warehouses end-to-end. Explore private links, conditional access, workspace roles, item-level permissions, and granular T-SQL controls for object, row, and column-level security. \nPlus, see dynamic data masking and OneLake security for SQL endpoints in action.", "u": "https://fabriccon.com/program/agenda?session=1064842", "tags": ["Admin & Governance", "Data Warehousing"]}, {"t": "Transition from Data Analyst to Data Engineer: Upgrading Skills from DataFlows Gen2 to Notebooks", "d": "2026-03-18", "s": "01:45 PM", "e": "02:45 PM", "tr": "Data Engineering, Data Integration", "ty": "Session", "l": "200", "sp": ["Thomas LeBlanc", "Nikola Ilic"], "desc": "The session shows an analyst how to use notebooks to perform the same actions as Dataflow Gen2. Looking at 4 areas: source, transformation, cleansing, and destination, examples include append/merge query to dataframe joins, text replace functionality, split and concatenate columns, as well as pivot/unpivot, data type changes, and removing duplicates. We will finish off with engine optimizations.", "u": "https://fabriccon.com/program/agenda?session=1075093", "tags": ["Data Engineering", "Data Integration"]}, {"t": "Fabric RTI and Agents in Sustainable Supply Chain Management", "d": "2026-03-18", "s": "01:45 PM", "e": "02:45 PM", "tr": "Real-Time Intelligence, Microsoft Foundry", "ty": "Session", "l": "200", "sp": ["Manisha Jha", "Tammiraju Prasanth"], "desc": "Our team has built a Supply Chain Management Solution for a Customer that deals with sustainable packaging for perishable products. Learn how Microsoft Fabric along with AI Foundry Agents helped this company achieve its targets and automate the whole process. We will focus on the Customer Case Study and the technical implementation details. Customer will share their experience during this session.", "u": "https://fabriccon.com/program/agenda?session=1080687", "tags": ["Microsoft Foundry", "Real-Time Intelligence"]}, {"t": "Build data-driven agents with Microsoft OneLake and Microsoft Foundry", "d": "2026-03-18", "s": "01:45 PM", "e": "02:45 PM", "tr": "Microsoft Foundry, OneLake", "ty": "Session", "l": "300", "sp": ["Farzad Sunavala", "Miquella de Boer"], "desc": "Join us for a strategic look at how OneLake and Foundry enable you to build AI apps that retrieve enterprise knowledge at scale. We'll show you how to unify all your data—across clouds and on-premises—into a single data lake and then highlight patterns for building agentic workflows that plan, reason, and iterate across this governed data, moving beyond RAG to orchestrate intelligent task flows.", "u": "https://fabriccon.com/program/agenda?session=1089168", "tags": ["Microsoft Foundry", "OneLake"]}, {"t": "Building Next-Gen Apps with Power Platform and SQL Server 2025", "d": "2026-03-18", "s": "01:45 PM", "e": "02:45 PM", "tr": "SQL Server, SQLCON, Power Platform", "ty": "Session", "l": "200", "sp": ["Alex Rostan", "Gaston Cruz"], "desc": "SQL Server 2025 introduces new capabilities that make it easier than ever to build secure, scalable applications with Power Platform. We’ll explore how to connect Power Apps to SQL 2025, take advantage of improved performance and security. You’ll learn best practices and architecture patterns that let you modernize your SQL-backed Bizz Apps with low code without rewriting your data layer.", "u": "https://fabriccon.com/program/agenda?session=1081209", "tags": ["SQL Server", "Power Platform", "SQLCON"]}, {"t": "Power Query Escape Room", "d": "2026-03-18", "s": "01:45 PM", "e": "02:45 PM", "tr": "Power BI, Data Dev", "ty": "Session", "l": "300", "sp": ["John Kerski", "Leslie Welch"], "desc": "The villainous Lord Taart Chart has stolen your curated data and locked it in his Azure Vault! Your mission: face 10 Power Query Puzzles that challenge your skills to wrangle, transform, and tame messy data. Can you outsmart him and reclaim your data before it’s lost forever?", "u": "https://fabriccon.com/program/agenda?session=1057981", "tags": ["Power BI", "Data Dev"]}, {"t": "Guardians of the lake: securing your data with OneLake", "d": "2026-03-18", "s": "01:45 PM", "e": "02:45 PM", "tr": "OneLake, Admin & Governance", "ty": "Session", "l": "200", "sp": ["Cole Haddock"], "desc": "Discover how Microsoft Fabric’s new OneLake security empowers you to protect sensitive data at scale with role-based access, row and column security, and governance best practices—turning OneLake into your secure foundation for analytics.", "u": "https://fabriccon.com/program/agenda?session=1052966", "tags": ["Admin & Governance", "OneLake"]}, {"t": "Mastering Fabric Data Agents: From Setup to Success", "d": "2026-03-18", "s": "01:45 PM", "e": "02:45 PM", "tr": "Data Science, Data Engineering", "ty": "Session", "l": "300", "sp": ["Marc Lelijveld"], "desc": "Fabric data agent has been available for a while, yet many implementations fall short of expectations. Without the right design, the agent may struggle to align with business context, produce inconsistent outputs, or require heavy manual intervention. \n\nIn this session, learn how to design smarter, more reliable agents by fine-tuning Agent Instructions, using the Data Agent SDK and training data sources.", "u": "https://fabriccon.com/program/agenda?session=1076052", "tags": ["Data Science", "Data Engineering"]}, {"t": "Dynamics 365 (Dataverse) integration with Fabric, and virtual tables over Fabric tables", "d": "2026-03-18", "s": "01:45 PM", "e": "02:45 PM", "tr": "Power Platform, Data Warehousing", "ty": "Session", "l": "300", "sp": ["Manas Maheshwari", "Jila \"JJ\" Yadav"], "desc": "Leverage first class integration with Dynamics 365 / Dataverse and other business data with Fabric to generate rich insights.", "u": "https://fabriccon.com/program/agenda?session=1089017", "tags": ["Power Platform", "Data Warehousing"]}, {"t": "Decoding Fabric Licensing", "d": "2026-03-18", "s": "01:45 PM", "e": "02:45 PM", "tr": "Admin & Governance", "ty": "Session", "l": "100", "sp": ["Kristyna Ferris"], "desc": "Navigate the complexities of Microsoft Fabric licensing with real-world scenarios. Learn the differences between Pro, Premium, and Fabric licenses. We will compare pricing models, estimate costs, and avoid budgeting traps to enable smarter, cost-savvy decisions about your data environment.", "u": "https://fabriccon.com/program/agenda?session=1020571", "tags": ["Admin & Governance"]}, {"t": "Touch your data with Real Time Intelligence", "d": "2026-03-18", "s": "01:45 PM", "e": "02:45 PM", "tr": "Real-Time Intelligence, Data Science", "ty": "Session", "l": "300", "sp": ["Dominick Raimato"], "desc": "Event driven data architectures are an easy way to drive quick insights and value.  Enter real time intelligence within Fabric.  This session will allow you to have a tangible experience by manipulating data within the room.  Leveraging devices, you will learn how to build your own physical proof of concept that will help you get buy in from your organization to make this part of your environment!", "u": "https://fabriccon.com/program/agenda?session=1081505", "tags": ["Data Science", "Real-Time Intelligence"]}, {"t": "Exploring Optimized Locking in SQL Server 2025", "d": "2026-03-18", "s": "01:45 PM", "e": "02:45 PM", "tr": "SQL Server, SQLCON, Azure SQL", "ty": "Session", "l": "300", "sp": ["John Morehouse"], "desc": "Updating data in SQL Server can lead to lock escalation, blocking, deadlocks, or slow performance if it isn't done correctly. The newly released optimized locking helps reduce these issues while improving concurrency. This session explores how it works—covering its architecture, implementation, and best practices to maximize performance to help reduce those dreaded locking issues!", "u": "https://fabriccon.com/program/agenda?session=1080442", "tags": ["SQL Server", "Azure SQL", "SQLCON"]}, {"t": "From Pipeline to Prompt: Powering Fabric AI for Conversational AI/Analytics", "d": "2026-03-18", "s": "01:45 PM", "e": "02:45 PM", "tr": "Data Integration", "ty": "Session", "l": "300", "sp": ["David Hrncir", "Kelly Kohlleffel"], "desc": "Is your AI strategy built on a foundation of sand? In the rush to adopt generative AI, many organizations overlook the most critical factor: AI is only as effective as the data feeding it. Join us to explore the frontier of end-to-end solutions within Microsoft Fabric. We’ll demonstrate how to bridge the gap between fragmented data sources and sophisticated Microsoft Copilot integrations. Learn how to transform stale, siloed information into a secure, fresh, and \"highly reliable\" data stream—the essential fuel for conversational analytics.  We’ll cover: harnessing AI and BI to move beyond static dashboards, required architecture for deep, real-time insights, and why data reliability is non-negotiable for AI success.  Don’t chase the hype.  Let’s push the envelope together!", "u": "https://fabriccon.com/program/agenda?session=1120421", "tags": ["Data Integration"]}, {"t": "Planning & Writeback on Top of Semantic Models", "d": "2026-03-18", "s": "01:45 PM", "e": "02:45 PM", "tr": "Power BI, Data Warehousing", "ty": "Session", "l": "100", "sp": ["Liran Edelist"], "desc": "Unlock hidden ROI by turning your existing semantic layer into a full planning engine. This innovation eliminates duplicate EPM systems, unifies actuals and plans, and delivers real-time, governed insights. By activating write-back directly to Fabric, organizations cut cost, boost agility, and transform planning into a seamless extension of analytics.", "u": "https://fabriccon.com/program/agenda?session=1081289", "tags": ["Power BI", "Data Warehousing"]}, {"t": "CORENOTE: Power BI Roadmap: Strategy, Vision, and Demos", "d": "2026-03-18", "s": "03:05 PM", "e": "04:05 PM", "tr": "Power BI", "ty": "CORENOTE", "l": "200", "sp": ["Nico Cristache", "Eun Hee Kim"], "desc": "Power BI empowers organizations to turn insights into actions and deliver enterprise analytics at scale in Fabric. In this session discover why businesses standardize on Power BI, learn about building a data-driven culture, and get a first look at upcoming features that unlock your data’s potential.", "u": "https://fabriccon.com/program/agenda?session=1060841", "tags": ["Power BI"]}, {"t": "CORENOTE: The Fabric Data Warehouse Future-Proof Advantage", "d": "2026-03-18", "s": "03:05 PM", "e": "04:05 PM", "tr": "Data Warehousing, Data Integration", "ty": "CORENOTE", "l": "100", "sp": ["Tino Tereshko"], "desc": "Fabric Data Warehouse has been built from the ground up in 2020s, inspired by industry state-of-the-art. In this session we unveil new features designed to make it easier to manage and get the most out of your analytics workloads with Fabric Data Warehouse.", "u": "https://fabriccon.com/program/agenda?session=1065098", "tags": ["Data Integration", "Data Warehousing"]}, {"t": "CORENOTE: Trusted AI starts with Fabric: unified real-time intelligence and IQ context", "d": "2026-03-18", "s": "03:05 PM", "e": "04:05 PM", "tr": "Real-Time Intelligence, Fabric IQ, Microsoft Foundry", "ty": "CORENOTE", "l": "100", "sp": ["Yitzhak Kesselman", "Tessa Kloster"], "desc": "Fabric unifies your data estate in OneLake, converges your real-time and analytical workloads into a single data platform, and layers a semantic foundation with ontologies to form a unified intelligence platform. It empowers teams and AI agents with a shared, governed understanding of the live state of your business and the operational actions to affect outcomes. Grounded in real-time signals from Fabric Real-Time Intelligence and shared context from Fabric IQ, teams and AI can reason in the language of your business and operate in tandem to drive measurable impact on your business objectives.", "u": "https://fabriccon.com/program/agenda?session=1072718", "tags": ["Microsoft Foundry", "Real-Time Intelligence", "Fabric IQ"]}, {"t": "CORENOTE: OneLake, the unified data lake for the era of AI", "d": "2026-03-18", "s": "03:05 PM", "e": "04:05 PM", "tr": "OneLake", "ty": "CORENOTE", "l": "200", "sp": ["Josh Caplan", "Dipti Borkar"], "desc": "Microsoft OneLake eliminates data silos with a single intelligent storage system and provides a unified access point for all your data. This session will show you the latest capabilities coming to OneLake designed to help you unify data across clouds, secure, govern, and improve data discoverability in the OneLake catalog, and enable data sharing across domains—ensuring all data is AI-ready.", "u": "https://fabriccon.com/program/agenda?session=1056101", "tags": ["OneLake"]}, {"t": "Change Tracking in SQL Server 2025: Exploring Change Event Streaming vs CDC", "d": "2026-03-18", "s": "03:05 PM", "e": "04:05 PM", "tr": "SQL Server, SQLCON", "ty": "Session", "l": "300", "sp": ["Deborah Melkin"], "desc": "Need to ship row level data changes for processing downstream? Change Data Capture (CDC) used to be the go-to option. But now there's a new choice with SQL Server 2025: Change Event Streaming (CES). Come and learn about their architectures as well as the pros and cons of each. Leave knowing which is going to work best for your scenario.", "u": "https://fabriccon.com/program/agenda?session=1077185", "tags": ["SQL Server", "SQLCON"]}, {"t": "SSMS 22 Unlocked: Features You’ve Been Waiting For", "d": "2026-03-18", "s": "03:05 PM", "e": "04:05 PM", "tr": "SQL Server, SQLCON, SQL in Fabric", "ty": "Session", "l": "200", "sp": ["Erin Stellato", "Makena Barickman"], "desc": "SQL Server Management Studio (SSMS) saw more updates in the last two years than a developer makes before release day. Missed them? Don't worry! We’ll showcase SSMS 22 from the installer to AI features and everything in between. Expect a whirlwind tour with demos including the new connection dialog, SQL Projects enhancements, the Query Hint tool, and editor and results grid improvements.", "u": "https://fabriccon.com/program/agenda?session=1089865", "tags": ["SQL Server", "SQLCON", "SQL in Fabric"]}, {"t": "Fabric Data Factory Orchestration: Build Pipelines + Airflow Like a Pro", "d": "2026-03-18", "s": "03:05 PM", "e": "04:05 PM", "tr": "Data Integration, Data Engineering", "ty": "Session", "l": "300", "sp": ["Mark Kromer", "Mario Zimmermann"], "desc": "Building pipelines in Fabric Data Factory is easy. But did you know that you can go beyond data pipelines and build powerful orchestration workflows in Fabric Data Factory that also include Python-based Apache Airflow DAGs? Learn everything you need to know about becoming an orchestration pro!", "u": "https://fabriccon.com/program/agenda?session=1041167", "tags": ["Data Engineering", "Data Integration"]}, {"t": "Deliver Trusted Data Products for Analytics and AI in Microsoft Fabric", "d": "2026-03-18", "s": "03:05 PM", "e": "04:05 PM", "tr": "Data Dev, Data Engineering", "ty": "Session", "l": "300", "sp": ["Craig Gravina"], "desc": "Microsoft Fabric accelerates analytics and AI at scale but without governed, trusted data, results fall short. This session’s demo showcases how data products, and semantic models, are utilized to succeed with data and AI initiatives. Learn how modern AI-driven, DataOps-built MDM delivers trusted data products into OneLake, enabling business and agentic users to succeed with high quality data.", "u": "https://fabriccon.com/program/agenda?session=1123263", "tags": ["Data Engineering", "Data Dev"]}, {"t": "Make Managed Self-Service BI Work for You with Power BI and Purview (the BI Mullet Approach)", "d": "2026-03-18", "s": "03:05 PM", "e": "04:05 PM", "tr": "Power BI, Microsoft Purview", "ty": "Session", "l": "100", "sp": ["Lenore Flower"], "desc": "When designed well, a managed self-service BI approach strikes the perfect balance between centralized data discipline and flexible self-service reporting. This session will demonstrate how smart Power BI implementation (including centrally maintained semantic models, report templates, and administration) saves time, money, and headaches when paired with Purview's Unified Catalog.", "u": "https://fabriccon.com/program/agenda?session=1081592", "tags": ["Power BI", "Microsoft Purview"]}, {"t": "Materialized Lake Views: Simplifying Your Medallion ETL", "d": "2026-03-18", "s": "03:05 PM", "e": "04:05 PM", "tr": "Data Engineering, Data Warehousing", "ty": "Session", "l": "200", "sp": ["Justin Cunningham"], "desc": "Materialized lake views turn Spark SQL into auto-orchestrated smart tables in your Fabric lakehouse. In this session, learn how to replace fragile ETL with declarative medallion layers, understand refresh and lineage, and decide when materialized lake views beat notebooks, jobs, or warehouses.", "u": "https://fabriccon.com/program/agenda?session=1081588", "tags": ["Data Engineering", "Data Warehousing"]}, {"t": "Build Secure, Scalable AI Applications with Azure SQL Database Hyperscale", "d": "2026-03-18", "s": "03:05 PM", "e": "04:05 PM", "tr": "Azure SQL, SQLCON", "ty": "Session", "l": "300", "sp": ["Aditya Badramraju", "Arvind Shyamsundar"], "desc": "Azure SQL Database Hyperscale eliminates the practical limits traditionally seen in cloud databases to support modern AI apps. Join us as we cover features like native vector indexes, semantic search, and low-latency RAG. We’ll show how Azure SQL Database Hyperscale can scale securely with up to 30 replicas and 150MBps log speed. We’ll show how to invoke models via T-SQL and Microsoft Foundry to modernize your mission-critical workloads.", "u": "https://fabriccon.com/program/agenda?session=1021624", "tags": ["SQLCON", "Azure SQL"]}, {"t": "Unlocking Copilot in Fabric: Administration, Governance, and Beyond!", "d": "2026-03-18", "s": "03:05 PM", "e": "04:05 PM", "tr": "Admin & Governance, Power BI", "ty": "Session", "l": "200", "sp": ["Dan English", "Sandeep Pawar"], "desc": "Join us for an engaging Copilot in Fabric session covering administration, governance, enablement strategies, and capacity management. We’ll also explore Data Agent, Standalone Copilot, Power BI Copilot, and how Microsoft Purview Data Security Posture Management (DSPM) for AI helps monitor AI use. We will cover real-world scenarios and best practices turning governance into a strategic advantage.", "u": "https://fabriccon.com/program/agenda?session=1079884", "tags": ["Power BI", "Admin & Governance"]}, {"t": "Empowering Fabric administrators: securing, scaling, and sustaining your data estate", "d": "2026-03-18", "s": "03:05 PM", "e": "04:05 PM", "tr": "Admin & Governance", "ty": "Session", "l": "", "sp": ["Arthi Ramasubramanian Iyer", "Cillian Mitchell"], "desc": "Join us to see how we are making the lives of Fabric administrators easier, expanding on some of their key daily tasks. We’ll explore how to protect data at scale, ensure it’s easy to find, keep capacities healthy, and strengthen network and data security, to build confidence, clarity, and resilience across your Fabric estate. This session will feature Kim Manis, the Corporate Vice President of Product Management for Microsoft Fabric.", "u": "https://fabriccon.com/program/agenda?session=1088784", "tags": ["Admin & Governance"]}, {"t": "Deployment Pipeline Patterns for Multi-Workspace Environments in Microsoft Fabric", "d": "2026-03-18", "s": "03:05 PM", "e": "04:05 PM", "tr": "Data Dev, Data Engineering", "ty": "Session", "l": "300", "sp": ["Aleksi Partanen", "Atte Sukari"], "desc": "Managing deployments across multiple workspaces per environment in Microsoft Fabric can be a challenge. Based on real projects, this session shows how to use Fabric Deployment Pipelines with proven patterns, tips, and best practices for handling cross workspace dependencies through autobinding and variable library strategies, supported by practical demos that highlight the most important concepts.", "u": "https://fabriccon.com/program/agenda?session=1061161", "tags": ["Data Engineering", "Data Dev"]}, {"t": "Choosing the Right Data Store--An Overview of Azure and Fabric Data Platform Choices", "d": "2026-03-18", "s": "03:05 PM", "e": "04:05 PM", "tr": "Azure SQL, SQLCON, Data Dev", "ty": "Session", "l": "200", "sp": ["Denny Cherry"], "desc": "Choosing the right data store can make or break the performance and costs of your application. In this session, we will cover all the options available to you in the Azure and Fabric Data space. You'll learn about CosmosDB, Azure/Fabric SQL DB, Postgres, and MySQL services, as well as Databricks.", "u": "https://fabriccon.com/program/agenda?session=1019901", "tags": ["SQLCON", "Azure SQL", "Data Dev"]}, {"t": "Securing Your Data Estate with Purview", "d": "2026-03-18", "s": "03:05 PM", "e": "04:05 PM", "tr": "Microsoft Purview, Admin & Governance", "ty": "Session", "l": "200", "sp": ["Marthe Moengen"], "desc": "As AI adoption grows, so does the importance of strong governance and compliance. Let's explore how Purview can support you Fabric environment! \n\nWe’ll cover key features like Data Loss Prevention (DLP), sensitivity labeling, and data access governance. What they do, and how they work in real-world scenarios, and where there may be opportunities to further mature your implementation.", "u": "https://fabriccon.com/program/agenda?session=1081288", "tags": ["Admin & Governance", "Microsoft Purview"]}, {"t": "Build Your AI Foundation with Fabric Metadata-driven Framework", "d": "2026-03-18", "s": "03:05 PM", "e": "04:05 PM", "tr": "Data Integration, SQL in Fabric", "ty": "Session", "l": "300", "sp": ["Erwin de Kreuk"], "desc": "Ready to learn how to build your AI foundation? Discover how Microsoft Fabric’s metadata-driven framework, combined with Data Factory and a Fabric database, powers automated data integration for AI-ready environments. Gain insights on governance, scalability, and accelerating AI-driven analytics.", "u": "https://fabriccon.com/program/agenda?session=1068734", "tags": ["Data Integration", "SQL in Fabric"]}, {"t": "Agentic AI for data engineering and vibe analytics on MS Fabric", "d": "2026-03-18", "s": "03:05 PM", "e": "04:05 PM", "tr": "Microsoft Foundry, Microsoft Foundry", "ty": "Session", "l": "300", "sp": ["Santosh Tiwari"], "desc": "This session introduces how Agentic AI combined with MS Fabric transforms data engineering and vibe analytics. How autonomous, goal-driven agents automate ingestion, transformation, and data quality with adaptability and governance? With Fabric’s unified offerings and vibe analytics on sentiment and behavior, organizations gain a faster, scalable, intelligent data ecosystem for smarter decisions.", "u": "https://fabriccon.com/program/agenda?session=1084297", "tags": ["Microsoft Foundry"]}, {"t": "Performance Management with Fabric:  The Next Frontier of Organizational Intelligence", "d": "2026-03-18", "s": "03:05 PM", "e": "04:05 PM", "tr": "Data Warehousing, Data Science", "ty": "Session", "l": "200", "sp": ["Richard Lamorena", "Noah Mattern"], "desc": "This session will explore how the principles behind \"Performance Management IQ\"—an analogy inspired by Microsoft’s new \"Work IQ,\" \"Fabric IQ,\" and \"Foundry IQ\" products—can be realized using Fabric as the central data platform for AI-ready insights.  Finance, operations, and HR data become harmonized in Fabric to enable powerful performance management insights for analytics, data science, and AI.", "u": "https://fabriccon.com/program/agenda?session=1081351", "tags": ["Data Science", "Data Warehousing"]}, {"t": "Fabric Partner Team: Ask Me Anything", "d": "2026-03-18", "s": "03:05 PM", "e": "04:05 PM", "tr": "No Track", "ty": "AMA", "l": "", "sp": ["Fabric Partner Team"], "desc": "Let’s talk partnership! We’re hosting an AMA with the Fabric Partner Success Team, and you’re invited. Whether you’re just getting started or looking to scale your Fabric practice, this is your chance to ask questions, get advice, and connect with the team supporting partner success. Don’t miss this opportunity to learn, share, and grow—see you there!", "u": "https://fabriccon.com/program/agenda?session=1139841", "tags": ["No Track"]}, {"t": "CORENOTE: Fabric Data Engineering Roadmap", "d": "2026-03-18", "s": "04:25 PM", "e": "05:25 PM", "tr": "Data Engineering", "ty": "CORENOTE", "l": "200", "sp": ["Justyna Lucznik"], "desc": "Fabric Data Engineering empowers data engineers to build out a lakehouse architecture and transform their data, at scale, using Spark. Join this session to learn more about the latest updates to Data Engineering in Fabric, as well as what's coming in the near future.", "u": "https://fabriccon.com/program/agenda?session=1042381", "tags": ["Data Engineering"]}, {"t": "CORENOTE: Building Agentic apps in Fabric with Cosmos DB and User Data Functions", "d": "2026-03-18", "s": "04:25 PM", "e": "05:25 PM", "tr": "Cosmos DB, Developer Experiences", "ty": "CORENOTE", "l": "300", "sp": ["Kirill Gavrylyuk", "Mark Brown"], "desc": "Join us to build a modern agentic app with Microsoft Fabric as the intelligent backend. Give your app agents memory using Cosmos DB and its fast semantic search over OneLake. Add real-time, event-driven, context-aware experiences to your app with User Data Functions, Cosmos DB two-way sync with OneLake, and Real-Time Intelligence.", "u": "https://fabriccon.com/program/agenda?session=1072378", "tags": ["Developer Experiences", "Cosmos DB"]}, {"t": "Transform Your Business with Fabric Real-Time Intelligence", "d": "2026-03-18", "s": "04:25 PM", "e": "05:25 PM", "tr": "Real-Time Intelligence", "ty": "Session", "l": "200", "sp": ["Devang Shah", "Kati Iceva"], "desc": "Real Time Intelligence helps businesses transform with real-time insights, analytics and actions built for the era of AI. This session will cover key features, capabilities, and the impact it has on operational efficiency and decision-making processes. We will also highlight customer success stories and showcase how you can revolutionize your data strategy and unlock new opportunities for growth.", "u": "https://fabriccon.com/program/agenda?session=1072716", "tags": ["Real-Time Intelligence"]}, {"t": "CORENOTE: Governing your data estate with Microsoft Purview Data Governance", "d": "2026-03-18", "s": "04:25 PM", "e": "05:25 PM", "tr": "Microsoft Purview", "ty": "CORENOTE", "l": "200", "sp": ["Shafiq Mannan", "Sita Dontharaju"], "desc": "Learn how Microsoft Purview Data Governance empowers users to democratize data with its enterprise catalog. This session will cover: \n\n1. Key Data Governance challenges  \n\n2. How Purview simplifies Data Governance \n\n3. New innovations within the Unified Catalog  \n\n4. End to end demo of Purview", "u": "https://fabriccon.com/program/agenda?session=1072516", "tags": ["Microsoft Purview"]}, {"t": "CI/CD processes in Microsoft Fabric: best practices and latest developments", "d": "2026-03-18", "s": "04:25 PM", "e": "05:25 PM", "tr": "Developer Experiences, Admin & Governance", "ty": "Session", "l": "200", "sp": ["Ali Hamud", "Ted Pattison"], "desc": "Join this session to explore the latest capabilities in Fabric for establishing scalable and resilient release processes. Gain practical insights to help you streamline and optimize your CI/CD processes and learn about upcoming advancements across the Fabric platform.", "u": "https://fabriccon.com/program/agenda?session=1048555", "tags": ["Developer Experiences", "Admin & Governance"]}, {"t": "Config-Driven Data Engineering in Microsoft Fabric", "d": "2026-03-18", "s": "04:25 PM", "e": "05:25 PM", "tr": "Data Engineering, Developer Experiences", "ty": "Session", "l": "300", "sp": ["Pierre LaFromboise"], "desc": "Data-engineering often results in hundreds of one-offs with duplicate code and inconsistency, making change slow, brittle, and costly. We will introduce and demo new metadata and config-driven patterns for PySpark integration in Fabric. You will learn to implement reusable patterns that simplify development, scale reliably, cut duplication, and improve governance across Fabric environments.", "u": "https://fabriccon.com/program/agenda?session=1051136", "tags": ["Developer Experiences", "Data Engineering"]}, {"t": "Accelerate Your Move to Microsoft Fabric: Key Steps, Common Pitfalls, and Best Practices", "d": "2026-03-18", "s": "04:25 PM", "e": "05:25 PM", "tr": "Developer Experiences, Admin & Governance", "ty": "Session", "l": "300", "sp": ["Keshav Polepalle", "Trilok Rajesh"], "desc": "Curious about how organizations cut months off their Microsoft Fabric migration timelines? We’ll share a proven roadmap, highlighting the stages of planning, migration, and optimization. We’ll also delve into common pitfalls to avoid—ensuring your journey remains on track and under budget.", "u": "https://fabriccon.com/program/agenda?session=1042254", "tags": ["Developer Experiences", "Admin & Governance"]}, {"t": "From Dev to Dashboard – Azure SQL vs Fabric SQL in Practice", "d": "2026-03-18", "s": "04:25 PM", "e": "05:25 PM", "tr": "SQL in Fabric, SQLCON, Azure SQL", "ty": "Session", "l": "300", "sp": ["Matthias Nohl"], "desc": "Should you run your analytics workloads in Azure SQL or Fabric SQL? This session compares architecture, performance, cost, and integration. Learn where each platform shines — from dev to operational reporting — and get a decision framework to choose the right SQL engine for your scenario.", "u": "https://fabriccon.com/program/agenda?session=1080723", "tags": ["SQLCON", "Azure SQL", "SQL in Fabric"]}, {"t": "Driving Cost-Efficient Data Architectures for SQL Server, Azure SQL and Fabric using FinOps", "d": "2026-03-18", "s": "04:25 PM", "e": "05:25 PM", "tr": "SQL Server, SQLCON, Admin & Governance", "ty": "Session", "l": "100", "sp": ["Hamish Watson"], "desc": "Learn how to optimise SQL Server, Azure SQL and Fabric costs using FinOps practices and AI-driven insights. We’ll explore key cost drivers, show how AI detects inefficiencies, forecasts spend, recommends right-sizing, and helps design smarter, cost-efficient data architectures across hybrid and cloud environments.", "u": "https://fabriccon.com/program/agenda?session=1080548", "tags": ["SQL Server", "Admin & Governance", "SQLCON"]}, {"t": "Building The Fabric Well-Architected Framework", "d": "2026-03-18", "s": "04:25 PM", "e": "05:25 PM", "tr": "Admin & Governance, Developer Experiences", "ty": "Session", "l": "300", "sp": ["Joey Dantoni"], "desc": "What is the best way to architect Fabric workspaces? How should your network and security models be built? In this session you will learn about best practices across Fabric for naming, deployment, capacity management, security and more.", "u": "https://fabriccon.com/program/agenda?session=1062655", "tags": ["Developer Experiences", "Admin & Governance"]}, {"t": "SQL Server 2025: The Developer’s Revolution", "d": "2026-03-18", "s": "04:25 PM", "e": "05:25 PM", "tr": "SQL Server, SQLCON, Azure SQL", "ty": "Session", "l": "300", "sp": ["Javier Villegas", "Gonzalo Bissio Bissio"], "desc": "Explore SQL Server 2025’s new dev features -JSON type, Regular Expressions, and Change Event Streaming for real-time pipelines. See how REST API and Data API Builder turn your data into secure, high-performance APIs. Packed with demos, this session is perfect for developers, DBAs, and architects", "u": "https://fabriccon.com/program/agenda?session=1070994", "tags": ["SQL Server", "Azure SQL", "SQLCON"]}, {"t": "Talk to Your Data: The Future of Data Interaction with AI", "d": "2026-03-18", "s": "04:25 PM", "e": "05:25 PM", "tr": "Azure SQL, SQLCON, Azure SQL", "ty": "Session", "l": "100", "sp": ["Danny Kruge"], "desc": "In the evolving world of data, the ability to interact with your datasets and databases using natural language is a game-changer. This session will introduce you to the power of Azure OpenAI, Azure SQL, and Microsoft Fabric, showing you how to break down barriers that have traditionally required.", "u": "https://fabriccon.com/program/agenda?session=1068733", "tags": ["SQLCON", "Azure SQL"]}, {"t": "Migration Paths from Azure Data Factory to Fabric Data Factory", "d": "2026-03-18", "s": "04:25 PM", "e": "05:25 PM", "tr": "Data Integration", "ty": "Session", "l": "200", "sp": ["Mark Kromer", "Pat Mahoney"], "desc": "Looking to simplify your data integration landscape while gaining the performance & cost efficiencies of Microsoft Fabric?\n\nWe’ll walk through Azure Data Factory, Synapse pipelines, Dataflows & MDF migrations to Fabric Data Factory.\n\nYou’ll learn how Fabric's data unification is a perfect fit for existing pipelines & dataflows, dramatically reducing operational overhead and introduce our new migration tools.", "u": "https://fabriccon.com/program/agenda?session=1093018", "tags": ["Data Integration"]}, {"t": "From Transactions to Analytics: Transforming MySQL Data with Fabric Mirroring", "d": "2026-03-18", "s": "04:25 PM", "e": "05:25 PM", "tr": "MySQL, MySQL", "ty": "Session", "l": "200", "sp": ["Avnish Rastogi"], "desc": "Fabric-enabled Azure Database for MySQL lets users replicate Azure MySQL Server data into Microsoft Fabric for real-time analytics and reporting - without ETL complexity. Discover its architecture, roadmap, and a live demo showing how Mirroring in Fabric unifies transactional and analytical insights.", "u": "https://fabriccon.com/program/agenda?session=1067908", "tags": ["MySQL"]}, {"t": "AI in Action: Microsoft Fabric for Data Science", "d": "2026-03-18", "s": "04:25 PM", "e": "05:25 PM", "tr": "Data Science, Data Engineering", "ty": "Session", "l": "200", "sp": ["Sadiq Ahmed"], "desc": "In this fast-paced, discover how Microsoft Fabric streamlines the entire AI workflow—from data exploration to model deployment. You’ll learn how to use it for data science, train models, and generate predictions all within Fabric’s unified analytics platform. Perfect for data professionals and AI enthusiasts looking to get started with Fabric in just one hour.", "u": "https://fabriccon.com/program/agenda?session=1043311", "tags": ["Data Science", "Data Engineering"]}, {"t": "Getting Started with Dataflow Gen2: Simple, Practical, Real", "d": "2026-03-18", "s": "04:25 PM", "e": "05:25 PM", "tr": "Data Integration, Power BI", "ty": "Session", "l": "200", "sp": ["Cristian Angyal"], "desc": "Want to get started with Dataflow Gen2 without stress? \nThis session explains what DFG2 is, why it matters, and how it fits into Microsoft Fabric. \nWe’ll build a dataflow from scratch, connect multiple data sources and apply proven Power Query patterns to clean messy data, consolidate files, reuse logic with parameters, publish to a Lakehouse, and configure a simple, reliable refresh.", "u": "https://fabriccon.com/program/agenda?session=1081425", "tags": ["Power BI", "Data Integration"]}, {"t": "From SQL SSIS to MS Fabric: Your ETL ReImagined", "d": "2026-03-18", "s": "04:25 PM", "e": "05:25 PM", "tr": "Data Integration, Data Engineering", "ty": "Session", "l": "200", "sp": ["Armando Lacerda"], "desc": "You're a SQL SSIS ninja, and now Microsoft Fabric is calling your ETL pipelines to the cloud. In this session, you will learn how to bridge your SSIS skills to the more scalable and more performant and integrated SaaS environment with live demos and feature comparisons.", "u": "https://fabriccon.com/program/agenda?session=1020597", "tags": ["Data Engineering", "Data Integration"]}, {"t": "AI-Driven MDM on Microsoft Fabric: Build the Intelligent Golden Record", "d": "2026-03-18", "s": "04:25 PM", "e": "05:25 PM", "tr": "Developer Experiences, Microsoft Foundry", "ty": "Session", "l": "100", "sp": ["Mehul Thacker"], "desc": "Discover how to build an AI-powered Master Data Management solution on Microsoft Fabric. Learn how AI models identify duplicates, enrich data, and create a reliable golden record. See practical patterns that improve data quality, downstream analytics, and enterprise operational efficiency.", "u": "https://fabriccon.com/program/agenda?session=1080995", "tags": ["Microsoft Foundry", "Developer Experiences"]}, {"t": "CI/CD and DevOps for Power BI: Beyond the Happy Path", "d": "2026-03-18", "s": "04:25 PM", "e": "05:25 PM", "tr": "Power BI, Admin & Governance", "ty": "Session", "l": "300", "sp": ["Edwin Van Megesen", "Amir Sarir"], "desc": "CI/CD is vital to efficient and governed Power BI delivery, yet Azure DevOps rarely follows the “happy path.” This session exposes the burden of manual steps, merge conflicts, and the limitations of GIT. Next, full-automated alternatives will be evaluated, covering zero-touch version control, enhanced lineage, advanced deployment workflows, and some of the associated pitfalls.", "u": "https://fabriccon.com/program/agenda?session=1077688", "tags": ["Power BI", "Admin & Governance"]}, {"t": "AI Answers, Done Right: When to use Power BI Copilot vs. Fabric Data Agents", "d": "2026-03-19", "s": "08:00 AM", "e": "09:00 AM", "tr": "Power BI", "ty": "Session", "l": "200", "sp": ["Sara Vredevoogd", "Carly Newsome"], "desc": "Business users want answers, not plumbing. In this session, we map when to use Power BI Copilot directly versus when Fabric Data Agents shine. We’ll cover the product’s current functionality to help you get started with AI, from setting up a data agent to chatting across all of your data in Power BI. We’ll highlight recent feature additions and talk about the roadmap of future investments to empower your business users in unlocking data insights with the help of Copilot.", "u": "https://fabriccon.com/program/agenda?session=1082152", "tags": ["Power BI"]}, {"t": "Building Trustworthy AI Applications with SQL: Ground to Cloud to Fabric", "d": "2026-03-19", "s": "08:00 AM", "e": "09:00 AM", "tr": "SQL Server, SQLCON, Azure SQL", "ty": "Session", "l": "400", "sp": ["Bob Ward"], "desc": "In today’s AI-driven landscape, trust underpins innovation. Organizations must deliver solutions while ensuring security, compliance, and data integrity. Get grounded in AI fundamentals, how AI “works”,  understand top AI trust challenges, and learn practical solutions. This session shows how tools like GitHub Copilot, Microsoft Foundry, Azure services, and Microsoft SQL help you build trustworthy AI applications with your data that scale from on premises to cloud and Microsoft Fabric.", "u": "https://fabriccon.com/program/agenda?session=1089708", "tags": ["SQL Server", "Azure SQL", "SQLCON"]}, {"t": "What’s new in Fabric capacities and capacity monitoring", "d": "2026-03-19", "s": "08:00 AM", "e": "09:00 AM", "tr": "Admin & Governance, Developer Experiences", "ty": "Session", "l": "200", "sp": ["Pankaj Arora", "Arsalan Yarveisi"], "desc": "Capacities are the foundation for all Microsoft Fabric workloads. This session will provide an overview of what’s new in Fabric capacities including new capacity governance capabilities that help you get ahead of outages and improvements to monitoring experiences in the Capacity Metrics App and Real Time Hub. We will also share best practices to help you better manage your capacities at scale.", "u": "https://fabriccon.com/program/agenda?session=1083898", "tags": ["Developer Experiences", "Admin & Governance"]}, {"t": "OneLake for SharePoint – From list and documents, to AI", "d": "2026-03-19", "s": "08:00 AM", "e": "09:00 AM", "tr": "Data Integration, OneLake", "ty": "Session", "l": "200", "sp": ["Shireen Bahadur", "Shiv Narayanan"], "desc": "Discover how OneLake brings SharePoint lists and documents into a unified data foundation, enabling seamless integration with Microsoft Fabric. Learn how to unlock AI-powered insights and analytics directly from your SharePoint content—transforming collaboration into intelligent decision-making.", "u": "https://fabriccon.com/program/agenda?session=1080541", "tags": ["Data Integration", "OneLake"]}, {"t": "From Simple Maps to Advanced Spatial Analytics in Power BI", "d": "2026-03-19", "s": "08:00 AM", "e": "09:00 AM", "tr": "Power BI", "ty": "Session", "l": "200", "sp": ["Vincent Dechandon"], "desc": "Explore the full spectrum of Location Intelligence in Power BI, from simple map coloring to advanced spatial analytics. Learn the core concepts behind mapping; how to choose the right geographies and map them with BI data; how to analyze data through proximity and travel times; and how to manage dynamic territories. Session will include native Power BI mapping capabilities as well as custom visuals.", "u": "https://fabriccon.com/program/agenda?session=1080262", "tags": ["Power BI"]}, {"t": "AI-Powered CI/CD for Microsoft Fabric: Building Enterprise-Grade Pipelines with GitHub Copilot", "d": "2026-03-19", "s": "08:00 AM", "e": "09:00 AM", "tr": "Developer Experiences, Data Engineering", "ty": "Session", "l": "400", "sp": ["Eugene Paden"], "desc": "Discover how AI transforms Fabric development! Learn our production-proven approach combining GitHub Copilot with Azure DevOps CI/CD for metadata-driven pipelines. We'll showcase automated notebook validation, security scanning, and AI-guided PR reviews—all without external dependencies. Real code, real results: from medallion architecture to zero-downtime deployments.", "u": "https://fabriccon.com/program/agenda?session=1073128", "tags": ["Developer Experiences", "Data Engineering"]}, {"t": "Enterprise security in Microsoft Fabric", "d": "2026-03-19", "s": "08:00 AM", "e": "09:00 AM", "tr": "Admin & Governance", "ty": "Session", "l": "200", "sp": ["Sarab Dua", "Bodhisatva Gautam"], "desc": "This session dives into Microsoft Fabric’s latest network and data security innovations like Outbound Access Protection, Azure Private Link, and Customer Managed Keys, all designed to protect sensitive information and simplify governance at scale. Learn how new governance features simplify enforcement and at-scale compliance.", "u": "https://fabriccon.com/program/agenda?session=1084696", "tags": ["Admin & Governance"]}, {"t": "The Genesis of Fabric Warehouse: A Deep Dive into Its Foundations", "d": "2026-03-19", "s": "08:00 AM", "e": "09:00 AM", "tr": "Data Warehousing, SQL in Fabric", "ty": "Session", "l": "300", "sp": ["Joanna Podgoetsky", "Jovan Popovic"], "desc": "Join us for an inside look at the evolution of the Fabric Warehouse. Discover how we built the industry’s first SaaS cloud-scale data warehouse built natively over an open data format and born into Microsoft Fabric. Explore innovations that deliver out-of-the-box performance at scale and get an exclusive preview of the cutting-edge features we’ve recently launched and what’s coming next.", "u": "https://fabriccon.com/program/agenda?session=1076963", "tags": ["Data Warehousing", "SQL in Fabric"]}, {"t": "Elevate SQL development with VS Code, GitHub Copilot and Microsoft SQL drivers", "d": "2026-03-19", "s": "08:00 AM", "e": "09:00 AM", "tr": "SQL Server, SQLCON, SQL Server", "ty": "Session", "l": "300", "sp": ["Carlos Robles", "David Levy"], "desc": "This demo-heavy session highlights the MSSQL extension for Visual Studio Code, now more robust with new AI-driven features to streamline SQL development. With GitHub Copilot, you can move faster from schema to code, generate data, explore relationships, and keep your app in sync. What’s new in connectivity for Python and other languages, enabling faster, more secure cross-platform development.", "u": "https://fabriccon.com/program/agenda?session=1089908", "tags": ["SQL Server", "SQLCON"]}, {"t": "From On-Prem to Next-Gen: Simplifying SQL Server Migrations", "d": "2026-03-19", "s": "08:00 AM", "e": "09:00 AM", "tr": "SQL Server, SQLCON, Azure SQL", "ty": "Session", "l": "300", "sp": ["Rob Carrol"], "desc": "Azure SQL Managed Instance Next-gen General Purpose delivers faster performance, greater scalability, and simplified management. In this session, learn how we migrated 1,000+ SQL Server databases at scale with near-zero downtime, and how Azure Arc’s new migration experience streamlines assessment, replication, monitoring, and cutover, making your SQL Server migrations smooth and predictable.", "u": "https://fabriccon.com/program/agenda?session=1080701", "tags": ["SQL Server", "Azure SQL", "SQLCON"]}, {"t": "SQL Server Sleuthing: Unmasking SQL Server Performance Issues", "d": "2026-03-19", "s": "08:00 AM", "e": "09:00 AM", "tr": "SQL Server, SQLCON, Developer Experiences", "ty": "Session", "l": "200", "sp": ["Monica Morehouse (Rathbun)"], "desc": "Dive into SQL Server performance like a true data detective. Learn how to analyze query plans, uncover hidden bottlenecks, and chase down the real culprits behind slow-running queries. We’ll break down key performance metrics, decode what they actually mean in the real world, and show you how to turn chaos into clarity. By the end, you’ll have the tools and confidence to keep your SQL Server environment running fast, stable, and drama-free. Join us for “SQL Unmasked” and start solving performance mysteries the smart (and fun) way.", "u": "https://fabriccon.com/program/agenda?session=1079704", "tags": ["SQL Server", "Developer Experiences", "SQLCON"]}, {"t": "Sharing Experiences: Customer Journeys migrating to Microsoft Fabric", "d": "2026-03-19", "s": "08:00 AM", "e": "09:00 AM", "tr": "No Track", "ty": "Customer Story", "l": "100", "sp": ["Art Cabugason", "Daniel Retzer"], "desc": "Join this session to hear firsthand from customers who have transformed their data estates with Microsoft Fabric. From global enterprises modernizing complex legacy systems to agile teams embracing Fabric native services, these stories highlight the strategies, challenges, and breakthroughs that defined their journeys. Discover how organizations accelerated time to value and unlocked new insights by harnessing Fabric’s unified platform.", "u": "https://fabriccon.com/program/agenda?session=1095263", "tags": ["No Track"]}, {"t": "Get Proactive: Building Autonomous Operations Agents with Fabric IQ", "d": "2026-03-19", "s": "08:00 AM", "e": "09:00 AM", "tr": "Real-Time Intelligence, Fabric IQ, Data Integration", "ty": "Session", "l": "200", "sp": ["Greg Nash"], "desc": "Traditional monitoring and alerting is reactive and teams spend valuable time manually analyzing data and coordinating responses. In this session, we will learn how to configure operations agents to autonomously monitor real-time data, reason over business context using semantic ontologies, and take actions automatically to optimize outcomes before issues escalate.", "u": "https://fabriccon.com/program/agenda?session=1080869", "tags": ["Real-Time Intelligence", "Data Integration", "Fabric IQ"]}, {"t": "SQL database in Fabric: Real-world Scenarios and Solutions", "d": "2026-03-19", "s": "08:00 AM", "e": "09:00 AM", "tr": "SQL in Fabric, SQLCON, Azure SQL", "ty": "Session", "l": "200", "sp": ["Pam Lahoud", "Sukhwant Kaur"], "desc": "SQL database in Fabric is simple, autonomous, and optimized for AI—but what does that mean for you and your organization? Join us to learn about real-world use cases from customers who are already using Fabric databases to drive innovation. Discover how they are building smarter, faster solutions in the age of AI—reducing complexity, accelerating time to value, and unlocking new opportunities.", "u": "https://fabriccon.com/program/agenda?session=1088825", "tags": ["SQLCON", "Azure SQL", "SQL in Fabric"]}, {"t": "The instant insights pipeline: OneLake shortcuts  + Dataverse + Power Apps", "d": "2026-03-19", "s": "08:00 AM", "e": "09:00 AM", "tr": "OneLake, Power Platform", "ty": "Session", "l": "200", "sp": ["Alex Rostan", "Gaston Cruz"], "desc": "What if your business apps could power real-time analytics without complex ETL? In this session, we’ll look at how Power Apps and Dataverse connect directly to Microsoft Fabric using OneLake shortcuts, so your data is available almost in real time. You’ll learn how it works and the key tips to build solutions where everyday business actions turn into insights within seconds.", "u": "https://fabriccon.com/program/agenda?session=1081204", "tags": ["Power Platform", "OneLake"]}, {"t": "Spark Performance Deep Dive: Configuration, Debugging, and Performance Tuning", "d": "2026-03-19", "s": "08:00 AM", "e": "09:00 AM", "tr": "Data Engineering", "ty": "Session", "l": "400", "sp": ["Tim Arif", "Ashit Gosalia"], "desc": "Unlock the full potential of Apache Spark with this in-depth session focused on performance optimization. We’ll explore advanced configuration strategies to fine-tune executors, memory, and partitioning for maximum efficiency. Learn how to leverage Spark’s built-in tools for debugging and monitoring, including the Spark UI and metrics, to identify bottlenecks and optimize workloads.", "u": "https://fabriccon.com/program/agenda?session=1075677", "tags": ["Data Engineering"]}, {"t": "Azure SQL Database, a great alternative to SQL Server Express or Standard", "d": "2026-03-19", "s": "08:00 AM", "e": "09:00 AM", "tr": "Azure SQL, SQLCON, SQL Server", "ty": "Session", "l": "200", "sp": ["Kelly Broekstra", "Warwick Rudd"], "desc": "Do you currently use SQL Server Express or Standard Edition to support third-party applications? Discover how moving to Azure SQL Database can reduce costs and administrative overhead. This session will cover the pros and cons. We’ll walk through real demos of ongoing management, and engage in an interactive discussion to help you decide if Azure SQL DB is right for your environment.", "u": "https://fabriccon.com/program/agenda?session=1079893", "tags": ["SQLCON", "Azure SQL", "SQL Server"]}, {"t": "Implement Enterprise Data Integration Patterns with Data Factory in Microsoft Fabric", "d": "2026-03-19", "s": "08:00 AM", "e": "09:00 AM", "tr": "Data Integration", "ty": "Session", "l": "300", "sp": ["Noelle Li", "Sean Mirabile"], "desc": "In this session, you’ll learn how to design and implement robust data integration patterns using Data Factory in Microsoft Fabric to create powerful solutions.", "u": "https://fabriccon.com/program/agenda?session=1060854", "tags": ["Data Integration"]}, {"t": "Enterprise-Grade Migration to Microsoft Fabric: Modernizing Lakehouses, Pipelines, Analytics & AI", "d": "2026-03-19", "s": "08:00 AM", "e": "09:00 AM", "tr": "Data Engineering, Data Integration", "ty": "Session", "l": "200", "sp": ["Lalit Goyal", "Tyler Stemm"], "desc": "Microsoft Fabric is rapidly becoming the unified platform of choice for enterprises seeking to modernize data engineering, analytics, and AI. But migration from Synapse, ADF, Snowflake, Databricks, and on-prem systems requires more than a lift-and-shift.", "u": "https://fabriccon.com/program/agenda?session=1080729", "tags": ["Data Engineering", "Data Integration"]}, {"t": "Accelerating Data and AI with Azure Databricks", "d": "2026-03-19", "s": "08:00 AM", "e": "09:00 AM", "tr": "Data Engineering, Data Integration, Data Science, Data Warehousing, Power BI, Azure Databricks", "ty": "Session", "l": "300", "sp": ["Robert Saxby", "Surya Sai Turaga"], "desc": "Get the most out of your investments with Azure Databricks. Learn how the deep integration in the Azure ecosystem accelerates workloads, optimizes performance, and maximizes value. See how the Databricks Data Intelligence Platform on Azure streamlines analytics and AI.", "u": "https://fabriccon.com/program/agenda?session=1127137", "tags": ["Data Warehousing", "Azure Databricks", "Data Science", "Data Engineering", "Power BI", "Data Integration"]}, {"t": "AI Agents, Power Platform and SQL for Next Gen Automation", "d": "2026-03-19", "s": "08:00 AM", "e": "09:00 AM", "tr": "Power Platform, Data Integration", "ty": "Session", "l": "300", "sp": ["Chike Eduputa"], "desc": "See how AI agents, Power Platform and SQL can replace legacy RPAs and manual processes. Learn patterns for using copilots, data agents, APIs and orchestration flows in Copilot Studio to modernize automation, reduce cost and transform business operations.", "u": "https://fabriccon.com/program/agenda?session=1080707", "tags": ["Power Platform", "Data Integration"]}, {"t": "Transform your data platform into an AI-ready foundation for growth", "d": "2026-03-19", "s": "09:30 AM", "e": "09:50 AM", "tr": "Data Engineering, Data Integration", "ty": "Session", "l": "200", "sp": ["Ravi Gunturu", "Rahul Athalye"], "desc": "Modernize your end-to-end data platform to Fabric and unlock AI/ML enabled potential in workloads, analytics, and collaboration.\nDuring this session, we will focus on agentic AI methods of automation during the migration process, achieving 60% improvement in productivity.", "u": "https://fabriccon.com/program/agenda?session=1081324", "tags": ["Data Engineering", "Data Integration"]}, {"t": "The Fabric Effect at CDW: Built by the Business, Supercharged by IT", "d": "2026-03-19", "s": "09:30 AM", "e": "09:50 AM", "tr": "Power BI, Real-Time Intelligence", "ty": "Session", "l": "100", "sp": ["Mwazanji Sakala", "Christopher Marcolis"], "desc": "See how CDW brought business and IT together to build something bigger. Christopher shows how he used Fabric to turn scattered data into a single operational portal that runs the business. Julie adds technical insights and reveals how partnership unlocked even more value. A fast, energetic look at the power user revolution inside Fabric.", "u": "https://fabriccon.com/program/agenda?session=1104230", "tags": ["Power BI", "Real-Time Intelligence"]}, {"t": "Fabric Capacity Under Control: Reduced Costs, Less Outages, Better User Experience", "d": "2026-03-19", "s": "09:30 AM", "e": "09:50 AM", "tr": "Power BI, Admin & Governance", "ty": "Session", "l": "200", "sp": ["Patrick Perrier"], "desc": "Everyone struggles with rising Power BI capacity costs, rogue behaviors, outage risks, and badly designed reports reaching the platform. This session shows how predictive monitoring helps you prevent issues early and optimize for capacity costs. With Wiiisdom’s insights, you’ll keep Power BI stable, efficient, and delivering a better user experience.", "u": "https://fabriccon.com/program/agenda?session=1118796", "tags": ["Power BI", "Admin & Governance"]}, {"t": "SQL Copilots Unveiled: Architecture, Workflows, and Use Cases", "d": "2026-03-19", "s": "10:10 AM", "e": "11:10 AM", "tr": "SQL Server, SQLCON, SQL in Fabric", "ty": "Session", "l": "300", "sp": ["Erin Stellato", "Carlos Robles"], "desc": "SQL Copilots are reshaping how users interact with SQL databases by accelerating query development, improving workflow efficiency, and enabling natural language interaction with complex SQL databases. This session provides a technical look at the architecture powering GitHub Copilot in SSMS, the MSSQL extension for VS Code, and Copilot for SQL database in Fabric.  We'll walk through top use cases and showcase real-world demos to help you maximize Copilot impact for your SQL database.", "u": "https://fabriccon.com/program/agenda?session=1089862", "tags": ["SQL Server", "SQLCON", "SQL in Fabric"]}, {"t": "What's New and What's Next for Power BI Visuals", "d": "2026-03-19", "s": "10:10 AM", "e": "11:10 AM", "tr": "Power BI", "ty": "Session", "l": "200", "sp": ["Jacinda Eng", "Harleen Kaur"], "desc": "Join this session with the Power BI Product team to discover the vision, innovation, and future of Power BI visuals! We'll dive into how our overarching goals and strategies shape our decision-making to build user-focused features. Through real-world examples of recent feature releases, we'll demonstrate how to enable impactful data storytelling. You'll also gain an exclusive preview of what’s next for Power BI visuals—both in the short and long term—helping you shape your data visualization journey.", "u": "https://fabriccon.com/program/agenda?session=1075113", "tags": ["Power BI"]}, {"t": "Accelerate Data Transformation with Dataflows Gen2 in Microsoft Fabric", "d": "2026-03-19", "s": "10:10 AM", "e": "11:10 AM", "tr": "Data Integration", "ty": "Session", "l": "200", "sp": ["Mihir Wagle", "Miguel Llopis"], "desc": "Dataflows Gen2 in Fabric Data Factory provides a low-code data transformation feature in Fabric that accelerates your time to production. The Dataflows Product Team will share future product plans and provide deep dive insights into how to take advantage of Dataflows Gen2 in Fabric.", "u": "https://fabriccon.com/program/agenda?session=1041763", "tags": ["Data Integration"]}, {"t": "Open interoperability: integrating Azure Databricks and OneLake", "d": "2026-03-19", "s": "10:10 AM", "e": "11:10 AM", "tr": "OneLake, Azure Databricks", "ty": "Session", "l": "300", "sp": ["Josh Caplan", "Anavi Nahar"], "desc": "Discover how Microsoft and Databricks are advancing open lakehouse architecture with interoperability between Azure Databricks and OneLake. Learn how shared data access, seamless integration, and new capabilities like mirroring, native reading, and future write support empower organizations to accelerate analytics, AI, and innovation without data duplication.", "u": "https://fabriccon.com/program/agenda?session=1088149", "tags": ["OneLake", "Azure Databricks"]}, {"t": "Fabric IQ: Unlock Enterprise AI with a Unified Semantic Layer", "d": "2026-03-19", "s": "10:10 AM", "e": "11:10 AM", "tr": "Real-Time Intelligence, Fabric IQ, Real-Time Intelligence", "ty": "Session", "l": "200", "sp": ["Chafia Aouissi", "Adam Lash"], "desc": "Without shared business definitions, AI agents give inconsistent answers and your teams waste time reconciling conflicting data. Fabric IQ creates a governed, shared semantic foundation that models your business spanning entities, relationships, and rules. See how Fabric IQ builds on existing assets like Power BI semantic models, binds with live data, and enables AI agents to answer richer questions. Learn to extend your semantic models, connect live data sources, and enable AI agents to drive intelligent, automated decisions.", "u": "https://fabriccon.com/program/agenda?session=1094675", "tags": ["Real-Time Intelligence", "Fabric IQ"]}, {"t": "Delta Lake in Fabric: Internals, Innovations, and What’s New in Delta 4.0", "d": "2026-03-19", "s": "10:10 AM", "e": "11:10 AM", "tr": "Data Engineering", "ty": "Session", "l": "300", "sp": ["Miles Cole", "Daniel Coelho"], "desc": "From Delta 4.0 to Microsoft’s latest runtime innovations, dive into how Delta features really work. Learn Liquid Clustering and when to use it, why file size matters and how to put table tuning on autopilot, how to compact tables dramatically faster, and much more. Leave a time-traveling Delta Lake wizard ready to build fast, flexible, and scalable tables that deliver high-performance at any scale", "u": "https://fabriccon.com/program/agenda?session=1081612", "tags": ["Data Engineering"]}, {"t": "Discipline at the core, flexibility at the edge – Plotting the course for Microsoft Fabric", "d": "2026-03-19", "s": "10:10 AM", "e": "11:10 AM", "tr": "Developer Experiences", "ty": "Session", "l": "", "sp": ["Matthew Roche"], "desc": "Disciplined foundations and flexible practices, built on clear requirements and responsibilities, drive successful implementations of Microsoft Fabric. Based on a core principle of Executive Sponsorship, explore how to enable scalable self-service, grow a thriving community for skills and best practice sharing, and apply the Fabric Adoption Roadmap to establish effective, sustainable governance.", "u": "https://fabriccon.com/program/agenda?session=1088782", "tags": ["Developer Experiences"]}, {"t": "SQL database in Fabric: The unified database for AI apps and analytics", "d": "2026-03-19", "s": "10:10 AM", "e": "11:10 AM", "tr": "SQL in Fabric, SQLCON", "ty": "Session", "l": "200", "sp": ["Anna Hoffman", "Yo-Lei Chen"], "desc": "Discover how SQL database in Fabric brings transactional and analytical workloads together in one cloud-native database. In this session, learn what's new from the product team, see demos and customer stories/scenarios, and take a look at the roadmap.", "u": "https://fabriccon.com/program/agenda?session=1090295", "tags": ["SQLCON", "SQL in Fabric"]}, {"t": "Lessons from the Trenches - Fabric Features That Would Have Changed My Data Warehouse Design", "d": "2026-03-19", "s": "10:10 AM", "e": "11:10 AM", "tr": "Data Warehousing", "ty": "Session", "l": "200", "sp": ["Ajay Punyapu"], "desc": "Ever built your Fabric data warehouse only to discover a new feature that would have saved weeks of effort? You’re not alone. This session dives into the underrated and emerging Fabric capabilities that every architect and engineer should know.\nThrough real implementation stories, we will cover what to revisit in your current designs & upcoming releases that can impact your Fabric ecosystem.", "u": "https://fabriccon.com/program/agenda?session=1080750", "tags": ["Data Warehousing"]}, {"t": "Building and Deploying Smarter Data Agents in Microsoft Fabric", "d": "2026-03-19", "s": "10:10 AM", "e": "11:10 AM", "tr": "Data Science", "ty": "Session", "l": "300", "sp": ["Misha Desai", "Amir Jafari"], "desc": "Learn how to build and deploy smarter data agents in Fabric. We’ll show how to add richer context, connect new data sources, and use the latest intelligent capabilities. You’ll also see how to enable your agent in MCP, Teams, M365, Foundry, and more—making insights available to users wherever they work.", "u": "https://fabriccon.com/program/agenda?session=1077598", "tags": ["Data Science"]}, {"t": "Power BI in Higher Education: Real Use Cases from Enrollment to Graduation", "d": "2026-03-19", "s": "10:10 AM", "e": "11:10 AM", "tr": "Power BI, Data Integration", "ty": "Session", "l": "200", "sp": ["Andrew Sommer", "Santhana Lakshmi Ponnurasan"], "desc": "Higher ed generates massive data across admissions, enrollment, advising, and alumni, often stuck in silos. This session shows how Power BI unifies it through real examples: funnels, trends, retention, student success, faculty workload, and outcomes. Learn to model complex structures, clean data, and build clear visuals you can apply immediately.", "u": "https://fabriccon.com/program/agenda?session=1081126", "tags": ["Power BI", "Data Integration"]}, {"t": "Sharing Experiences: AI and Agentic Apps: Real World Transformation with Microsoft Fabric", "d": "2026-03-19", "s": "10:10 AM", "e": "11:10 AM", "tr": "Cosmos DB", "ty": "Customer Story", "l": "", "sp": ["Logan Finke", "Luis Baldini"], "desc": "AI and agentic applications are reshaping how businesses operate—moving from manual processes to intelligent, proactive workflows. Microsoft Fabric provides the unified data foundation that makes these innovations possible. In this session, you’ll hear real stories from customers who have embraced AI and agentic apps, showcasing how Fabric enabled them to accelerate insights, automate operations, and unlock new value across their organizations.", "u": "https://fabriccon.com/program/agenda?session=1095268", "tags": ["Cosmos DB"]}, {"t": "How Much is Fabric | Strategies for Managing and Estimating Fabric Capacity Expense", "d": "2026-03-19", "s": "10:10 AM", "e": "11:10 AM", "tr": "Admin & Governance, Data Dev", "ty": "Session", "l": "100", "sp": ["Nathan Giullian", "Jim Hill"], "desc": "Learn how to accurately estimate and control Microsoft Fabric capacity costs in today’s cloud‑driven world. We’ll cover key drivers like workload patterns, utilization, and scaling, and walk through practical models, examples, and best practices to align Fabric spend with your organization’s performance and budget goals.", "u": "https://fabriccon.com/program/agenda?session=1077884", "tags": ["Admin & Governance", "Data Dev"]}, {"t": "Best Practices for SQL Database Backup Configuration, Immutability, and Ransomware Protection", "d": "2026-03-19", "s": "10:10 AM", "e": "11:10 AM", "tr": "Azure SQL, SQLCON, Admin & Governance", "ty": "Session", "l": "300", "sp": ["Dinakar Nethi", "Rajesh Setlem"], "desc": "Learn best practices for Azure SQL Database backup configuration and ransomware protection. Explore PITR and LTR strategies, backup immutability, and deletion safeguards to ensure compliance and resilience. Gain actionable insights to secure data, prevent tampering, and maintain business continuity.", "u": "https://fabriccon.com/program/agenda?session=1089215", "tags": ["SQLCON", "Azure SQL", "Admin & Governance"]}, {"t": "Turn It On: The Power of Query Store for Rapid Performance Tuning", "d": "2026-03-19", "s": "10:10 AM", "e": "11:10 AM", "tr": "SQL Server, SQLCON, Azure SQL", "ty": "Session", "l": "200", "sp": ["Monica Morehouse (Rathbun)"], "desc": "I rely on Query Store every day—it lets me uncover performance issues in minutes, even without knowing the app code. If you want real insight into plan choices, regressions, and control over execution plans, you need to turn it on. Learn how to configure it, use its DMVs, spot plan changes fast, and finally answer, “Why was my query slow?”", "u": "https://fabriccon.com/program/agenda?session=1079709", "tags": ["SQL Server", "Azure SQL", "SQLCON"]}, {"t": "Trusted Analytics: Data Quality in Microsoft Fabric & Purview", "d": "2026-03-19", "s": "10:10 AM", "e": "11:10 AM", "tr": "Microsoft Purview, Admin & Governance", "ty": "Session", "l": "200", "sp": ["Wolfgang Strasser", "Shafiq Mannan"], "desc": "Unlock next-level data quality with the combined power of Microsoft Purview and Fabric. Discover how Fabric’s built-in governance creates truly trusted data assets, while Purview’s profiling, rules, scoring, and alerts deliver end-to-end visibility across lakehouses, warehouses, and semantic models. Leave with practical steps to confidently govern, monitor, and elevate your data quality.", "u": "https://fabriccon.com/program/agenda?session=1079113", "tags": ["Admin & Governance", "Microsoft Purview"]}, {"t": "Redefining Enterprise Planning for the Era of AI", "d": "2026-03-19", "s": "10:10 AM", "e": "11:10 AM", "tr": "Power BI", "ty": "Session", "l": "", "sp": ["Dipti Borkar"], "desc": "Enterprises face growing pressure to make faster, better decisions, yet many operate across fragmented systems and siloed data. In this session, we’ll explore how Microsoft Fabric brings data, insights, and action together on a unified platform—reducing complexity and accelerating decision making. In this session, we will explore the capabilities of Microsoft Fabric designed to assist organizations in transitioning from fragmented analysis to coordinated execution. These tools empower leaders to respond efficiently to change, extend intelligence throughout teams, and establish a robust foundation for AI-driven growth.", "u": "https://fabriccon.com/program/agenda?session=1141637", "tags": ["Power BI"]}, {"t": "Enhancing Resiliency in Fabric via Item Recovery, Item Identity Architecture, and More", "d": "2026-03-19", "s": "10:10 AM", "e": "11:10 AM", "tr": "Admin & Governance, Developer Experiences", "ty": "Session", "l": "300", "sp": ["Yulia Turchin", "Meenal Srivastva"], "desc": "Join us for a fast‑paced look at the latest advancements in item recovery, item creation policies, and new audit and access activity logging that provide clear insight into who accessed what, when, and how.\nWe’ll also highlight the broader set of investments transforming reliability and consistency across Microsoft Fabric. This includes concrete improvements that enhance customer experience and the Item Identity initiative, which ensures continuity even when item owners change or leave the organization. We’ll also explore our efforts to standardize item implementation across Fabric, helping eliminate issues caused by system‑generated items like staging lakehouses and warehouses.", "u": "https://fabriccon.com/program/agenda?session=1084597", "tags": ["Developer Experiences", "Admin & Governance"]}, {"t": "Unity in Action – Building Enterprise AI on a Unified Semantic Foundation", "d": "2026-03-19", "s": "10:10 AM", "e": "11:10 AM", "tr": "Data Engineering, Fabric IQ, Real-Time Intelligence", "ty": "Session", "l": "300", "sp": ["Subbu Muthukrishnan", "Chandler Stevens"], "desc": "Enterprise AI requires unified semantic foundations where governance and intelligence flow seamlessly. Learn to architect data platform that use Ontology as your semantic backbone, Data Agents for insights, and Operational Agents for action. Through real-world examples, discover how organizations use AI agents to reliably detect, contextualize, attribute, and act on governed data.", "u": "https://fabriccon.com/program/agenda?session=1102714", "tags": ["Data Engineering", "Fabric IQ", "Real-Time Intelligence"]}, {"t": "Fabric Native MDM: AI and Analytics Ready Data in Minutes", "d": "2026-03-19", "s": "10:10 AM", "e": "11:10 AM", "tr": "OneLake", "ty": "Session", "l": "200", "sp": ["Eric Melcher", "Roy Hasson"], "desc": "Most Microsoft Fabric initiatives don’t fail because of dashboards or models, they stall when the underlying data isn’t trusted.\n\nJoin us for building a production-ready master data management (MDM) solution natively in Microsoft Fabric. From proof of concept to go-live, you’ll see the full MDM lifecycle in action.\n\nWe’ll model data domains, configure integrations, connect source systems, define matching rules, apply data quality policies, and activate stewardship workflows to stop issues before they spread. We’ll publish clean, trusted, gold-medallion master data to OneLake for immediate use in Power BI and other Fabric workloads.\n\nYou’ll leave knowing what “done right” looks like in Fabric, the key implementation decisions, and how to accelerate time to value with governed, trusted data.", "u": "https://fabriccon.com/program/agenda?session=1121700", "tags": ["OneLake"]}, {"t": "Optimizing Workloads on Azure PostgreSQL Flexible Server: Best Practices for Speed & Scale", "d": "2026-03-19", "s": "10:10 AM", "e": "11:10 AM", "tr": "PostgreSQL, Admin & Governance", "ty": "Session", "l": "200", "sp": ["Surbhi Pokharna"], "desc": "Explore how to get peak performance from Azure PostgreSQL Flexible Server. We cover compute tiers, storage tuning, autoscaling, connection management, and monitoring essentials to ensure your PostgreSQL workloads run reliably and efficiently at any scale.", "u": "https://fabriccon.com/program/agenda?session=1080766", "tags": ["PostgreSQL", "Admin & Governance"]}, {"t": "Agentic Development in Power BI for the Non-Developer", "d": "2026-03-19", "s": "11:30 AM", "e": "12:30 PM", "tr": "Power BI", "ty": "Session", "l": "200", "sp": ["Emily Lisa", "Tori Pinheiro"], "desc": "Feeling underwater keeping up with AI change? This session breaks the buzzwords into clear, practical ideas. We explain what agentic development means for Power BI today, how large language models, skills, and tools work together, and how these capabilities show up in GitHub Copilot and web experiences. We’ll demo going from raw data to a usable model and show how the same foundations power reporting, chat with your data, and data agents", "u": "https://fabriccon.com/program/agenda?session=1082171", "tags": ["Power BI"]}, {"t": "New in modern Developer Experiences in SQL", "d": "2026-03-19", "s": "11:30 AM", "e": "12:30 PM", "tr": "SQL Server, SQLCON, Data Dev", "ty": "Session", "l": "300", "sp": ["Davide Mauri"], "desc": "Discover the most developer-focused SQL Server release in a decade! Explore new capabilities like JSON and Vector data types, advanced functions and indexing, Change Event Streams, improvement to query optimizer, plus powerful string functions like regular expression and string similarity search. Better integrate compute with data for improved efficiency and scalability of your solutions.", "u": "https://fabriccon.com/program/agenda?session=1092360", "tags": ["SQL Server", "SQLCON", "Data Dev"]}, {"t": "Business Continuity for SQL Server 2025 and Azure SQL Deployments", "d": "2026-03-19", "s": "11:30 AM", "e": "12:30 PM", "tr": "SQL Server, SQLCON", "ty": "Session", "l": "200", "sp": ["Matt Hyon", "Allan Hirt"], "desc": "Availability is a core tenet for any application using SQL Server 2025 or Azure SQL. You'll not only learn what's new in SQL Server 2025 and Azure SQL to see how you can meet your availability objectives and keep the business going, but also real world tips, tricks, dos, and don'ts for successful availability configurations on premises, hybrid, or in the cloud to be an availability hero back home.", "u": "https://fabriccon.com/program/agenda?session=1089733", "tags": ["SQL Server", "SQLCON"]}, {"t": "Microsoft Fabric AI: Copilots, Data Agents & Real‑World Extensions", "d": "2026-03-19", "s": "11:30 AM", "e": "12:30 PM", "tr": "Data Science, Microsoft Foundry", "ty": "Session", "l": "300", "sp": ["Bradley Ball"], "desc": "Build RAG patterns in minutes. We’ll show data agents, prompts, complex queries, and connecting to Microsoft Fabric data. Explore Copilots across services—what they are, how they differ—extend data agents from Fabric to Copilot Studio, to Microsoft Teams, M365 Copilot, Microsoft Foundry, and the Python SDK.  After we build this out, let's test Row Level and Column level security in our agents!", "u": "https://fabriccon.com/program/agenda?session=1020444", "tags": ["Data Science", "Microsoft Foundry"]}, {"t": "Enterprise Row-Level Security: A Blueprint for Scale in Fabric", "d": "2026-03-19", "s": "11:30 AM", "e": "12:30 PM", "tr": "Power BI, Admin & Governance", "ty": "Session", "l": "300", "sp": ["Karl Pover"], "desc": "Managing RLS for 100s of users across multiple semantic models becomes chaos fast. We'll share a proven architecture for complex security—VPs see regions, managers see departments, reps see customers. Learn reusable RLS table design, AD Group patterns to prevent role sprawl, performance tips, and self-service access reports. Walk away with a blueprint from production managing 500+ users.", "u": "https://fabriccon.com/program/agenda?session=1081313", "tags": ["Power BI", "Admin & Governance"]}, {"t": "Mirroring for  SQL Server in Fabric: Inside the Replication Process", "d": "2026-03-19", "s": "11:30 AM", "e": "12:30 PM", "tr": "Data Integration, Azure SQL", "ty": "Session", "l": "300", "sp": ["Meagan Longoria", "Justin Cunningham"], "desc": "Explore how Mirroring for SQL Server in Fabric really works: what happens on the source database, how data lands in OneLake, data retention policies, monitoring and logging, configuration of replicated objects, and which scenarios require restarting replication.", "u": "https://fabriccon.com/program/agenda?session=1062245", "tags": ["Azure SQL", "Data Integration"]}, {"t": "Build Your First Digital Employee: A Guide to Operations Agent in Fabric", "d": "2026-03-19", "s": "11:30 AM", "e": "12:30 PM", "tr": "Real-Time Intelligence, Fabric IQ, Microsoft Foundry", "ty": "Session", "l": "200", "sp": ["Kati Iceva", "Italo Lima"], "desc": "Manually monitoring pipelines, handling incidents, and executing workflows doesn't scale and it burns out your team. Operations agents in Microsoft Fabric provide true autonomy by handling these tasks independently. Explore how to architect agents that monitor pipelines, respond to incidents, and execute complex workflows without human intervention. Learn to configure agent rules, establish governance guardrails, and scale your operations with AI-driven reliability.", "u": "https://fabriccon.com/program/agenda?session=1080563", "tags": ["Microsoft Foundry", "Real-Time Intelligence", "Fabric IQ"]}, {"t": "Azure SQL Database vs. SQL Database in Fabric: Key Differences for Developers and DBAs", "d": "2026-03-19", "s": "11:30 AM", "e": "12:30 PM", "tr": "SQL in Fabric, SQLCON, Azure SQL", "ty": "Session", "l": "200", "sp": ["John Morehouse"], "desc": "Curious about the differences between Azure SQL Database and SQL database in Fabric? This session is perfect for developers and DBAs looking to understand the core architecture differences of these two platforms. Whether you’re optimizing an existing solution or planning your next project, this session will help you make informed decisions & maximize the value of these services.", "u": "https://fabriccon.com/program/agenda?session=1080439", "tags": ["SQLCON", "Azure SQL", "SQL in Fabric"]}, {"t": "Build Better, Ship Faster, Developer Experiences in Fabric Warehouse", "d": "2026-03-19", "s": "11:30 AM", "e": "12:30 PM", "tr": "Data Warehousing", "ty": "Session", "l": "100", "sp": ["Venkata Satya Pradeep Srikakolapu"], "desc": "Modern data teams expect warehouse development focused on developer experience and speed. This session shows how Fabric Warehouse delivers developer‑first workflows with familiar tools, Git‑based CI/CD, and AI Fabric skills to build and deploy with confidence. We close with a customer story using Mirroring, Fabric Warehouse, and dbt to ship a production analytics pipeline faster with higher reliability and business impact.", "u": "https://fabriccon.com/program/agenda?session=1081632", "tags": ["Data Warehousing"]}, {"t": "Building a Microsoft Fabric CoE That Works: What We Learned and How You Can Start", "d": "2026-03-19", "s": "11:30 AM", "e": "12:30 PM", "tr": "Admin & Governance, Diversity, Equity & Inclusion", "ty": "Session", "l": "100", "sp": ["Jared Brown", "Sam Kelly"], "desc": "Whether you’re a Microsoft Fabric/Power BI enterprise architect or a grassroots champion, learn how you can take steps towards establishing an approachable Microsoft Fabric Center of Excellence that grows with your organization. We’ll share real lessons on enablement, distributing best practices, hosting office hours, and how a simple start became a launchpad for inclusive community & governance.", "u": "https://fabriccon.com/program/agenda?session=1081347", "tags": ["Diversity", "Admin & Governance", "Equity & Inclusion"]}, {"t": "A Guide to Making the Most of your SQL Skills Using Microsoft Fabric", "d": "2026-03-19", "s": "11:30 AM", "e": "12:30 PM", "tr": "SQL in Fabric, SQLCON, Data Warehousing", "ty": "Session", "l": "300", "sp": ["Shabnam Watson"], "desc": "Don’t start over. Learn how SQL professionals can leverage their existing skills in Microsoft Fabric.  No need to learn PySpark or new data engineering tools. Discover how SQL powers Lakehouses, Warehouses, Real-Time Intelligence, and Notebooks. See why, for many tasks, SQL is not only compatible but often the most efficient way to build modern, scalable, intelligent data solutions in Fabric.", "u": "https://fabriccon.com/program/agenda?session=1076964", "tags": ["SQLCON", "Data Warehousing", "SQL in Fabric"]}, {"t": "Monitor and troubleshoot your data solution in Microsoft Fabric", "d": "2026-03-19", "s": "11:30 AM", "e": "12:30 PM", "tr": "Developer Experiences", "ty": "Session", "l": "200", "sp": ["Li Liu", "Joe Muziki"], "desc": "This session explores how users can monitor job statuses, understand the performance of their data solutions, and diagnose and address health issues in Fabric. We'll give you best practices and highlight the latest capabilities in Fabric to help you efficiently monitor and troubleshoot your data solutions.", "u": "https://fabriccon.com/program/agenda?session=1084819", "tags": ["Developer Experiences"]}, {"t": "Adapting to Fabric Spark: A SQL Server Practitioner’s Path Forward", "d": "2026-03-19", "s": "11:30 AM", "e": "12:30 PM", "tr": "Data Engineering, Data Warehousing", "ty": "Session", "l": "300", "sp": ["Christian Henrik Reich"], "desc": "This workshop is for SQL Server practitioners, used to reading query plans and caring about stats, stepping into Fabric. It covers Lakehouses and Spark, showing how your skills still apply in:\n\n* Understanding the Spark engine\n* Reading query plans and statistics\n* Using the Delta Lake engine\n\nThe takeaway is that approaches might differ, but the knowledge carries over.", "u": "https://fabriccon.com/program/agenda?session=1080695", "tags": ["Data Engineering", "Data Warehousing"]}, {"t": "Performance Tuning Tips for Fabric Data Factory", "d": "2026-03-19", "s": "11:30 AM", "e": "12:30 PM", "tr": "Data Integration, Data Engineering", "ty": "Session", "l": "300", "sp": ["Mohan Sankaran", "Chris Webb"], "desc": "Join us for an in-depth session on Performance Tuning Tips for Fabric Data Factory, with a focus on the Dataflow Gen2, Pipeline, and Copy Job artifacts.\n\nDiscover strategies to optimize your data workflows, enhance efficiency, and maximize performance. Don’t miss out on expert insights that can revolutionize your data management practices.", "u": "https://fabriccon.com/program/agenda?session=1080567", "tags": ["Data Engineering", "Data Integration"]}, {"t": "Real-Time Intelligence Meets Location: How Maps in Microsoft Fabric Transform Your Analytics", "d": "2026-03-19", "s": "11:30 AM", "e": "12:30 PM", "tr": "Real-Time Intelligence, Power BI", "ty": "Session", "l": "300", "sp": ["James Dales"], "desc": "Learn how Microsoft Fabric brings real-time and location intelligence together. Stream and transform live data with Real-Time Intelligence, visualize it instantly with Maps in Fabric, and then use Power BI to build interactive, rich geospatial analytics. In this demo-heavy session, we'll build the end-to-end solutions using real life data sources and examples.", "u": "https://fabriccon.com/program/agenda?session=1080153", "tags": ["Power BI", "Real-Time Intelligence"]}, {"t": "Peachy Migrations: Sweet Moves from Synapse to Fabric", "d": "2026-03-19", "s": "11:30 AM", "e": "12:30 PM", "tr": "Data Warehousing", "ty": "Session", "l": "300", "sp": ["Rob Carrol"], "desc": "Ready to make your analytics sweeter? Learn why migrating to Fabric’s OneLake architecture and AI-driven features beats Synapse for speed, governance, and insights. In this demo-driven session based on real-world migrations, learn practical steps, compatibility fixes, and how tools like the Fabric Migration Assistant make moving to Fabric Data Warehouse as smooth as a Georgia peach.", "u": "https://fabriccon.com/program/agenda?session=1080672", "tags": ["Data Warehousing"]}, {"t": "Busy is a Four-Letter Word", "d": "2026-03-19", "s": "11:30 AM", "e": "12:30 PM", "tr": "Diversity, Equity & Inclusion", "ty": "Session", "l": "100", "sp": ["Jes Chapman"], "desc": "If I ask you, \"How are you?\", is your default answer, \"I'm so busy!\"? Why do we measure our worth by how much we are doing, rather than by the value of what we do?  What does this have to do with a technical conference? Join me as I share with you how I, too, was too busy for too long, but am learning how to do less, be more productive, and have bigger impact at work, the community, and at home.", "u": "https://fabriccon.com/program/agenda?session=1080310", "tags": ["Diversity", "Equity & Inclusion"]}, {"t": "Enforce your governance and security regulations in Fabric", "d": "2026-03-19", "s": "11:30 AM", "e": "12:30 PM", "tr": "Admin & Governance", "ty": "Session", "l": "200", "sp": ["Anton Fritz", "Yael Biss"], "desc": "Join this session to discover the latest in Fabric security and governance enhancements:\n• New policies which allow Fabric admins to define precise, flexible controls in one central place. \n• New Purview security integrations which enable security admins to apply adaptive protection to sensitive data in Fabric.", "u": "https://fabriccon.com/program/agenda?session=1046193", "tags": ["Admin & Governance"]}, {"t": "SAP Data Integration Made Easy: From SAP to Fabric in Real Time", "d": "2026-03-19", "s": "11:30 AM", "e": "12:30 PM", "tr": "Data Integration, OneLake", "ty": "Session", "l": "100", "sp": ["Philipp Kiencke"], "desc": "In this session, we showcase our SAP Clean Core Certified integration with Microsoft Fabric, enabling seamless, real-time replication into OneLake. Discover how to simplify SAP data workflows, accelerate insights with ready-to-use pipelines, and apply proven best practices—supported by a live demo and guidance from dab experts.", "u": "https://fabriccon.com/program/agenda?session=1079597", "tags": ["Data Integration", "OneLake"]}, {"t": "Engineering Fabric at Scale: Accelerating Time to Value", "d": "2026-03-19", "s": "11:30 AM", "e": "12:30 PM", "tr": "Data Warehousing, OneLake", "ty": "Session", "l": "100", "sp": ["Eugene Grib", "Shishir Tejpal"], "desc": "PwC and a global software client unpack how they re-engineered a large-scale data platform on Microsoft Fabric to help meet ambitious service-level agreements (SLAs) and accelerate business value. This technical deep dive covers hybrid Lakehouse–Warehouse design, metadata-driven ingestion, performance tuning, and early adoption of new Fabric capabilities for an AI-ready foundation.", "u": "https://fabriccon.com/program/agenda?session=1081602", "tags": ["OneLake", "Data Warehousing"]}, {"t": "Bulletproof Your Dataflows: Error Handling and Data Quality in Fabric", "d": "2026-03-19", "s": "11:30 AM", "e": "12:30 PM", "tr": "Data Integration, Power BI", "ty": "Session", "l": "200", "sp": ["Cristian Angyal"], "desc": "Modern data solutions depend on reliable pipelines, yet error handling and data quality checks are often overlooked until failures occur in production. This session dives deep into building resilient Dataflows Gen2 solutions leveraging try/otherwise, structured error outputs, custom error messages, and partial failure patterns, centralizing error logs in dedicated tables for downstream monitoring.", "u": "https://fabriccon.com/program/agenda?session=1081395", "tags": ["Power BI", "Data Integration"]}, {"t": "Women in Data: Leading the Way", "d": "2026-03-19", "s": "12:30 PM", "e": "01:45 PM", "tr": "Diversity, Equity & Inclusion", "ty": "Special Event", "l": "100", "sp": ["Rie Merritt", "Wangui McKelvey", "Erin Stellato", "Priya Sathy", "Karen Thorson"], "desc": "Join us for an inspiring panel discussion featuring leading women in the field of data. This session will cover a range of topics from technical career discussions & guidance, overcoming challenges, the value of a strong network, where tech is going in the future. All with a special focus on being a woman in a technical field.\n\nWhether you are just starting your career, looking to advance or searching for a way help others, this panel will provide valuable insights and practical advice to help you navigate the dynamic world of data.", "u": "https://fabriccon.com/program/agenda?session=1113781", "tags": ["Diversity", "Equity & Inclusion"]}, {"t": "Where Data Meets Opportunity: Drive Business Value with Location Insights", "d": "2026-03-19", "s": "01:00 PM", "e": "01:20 PM", "tr": "Data Integration, Data Science", "ty": "Session", "l": "100", "sp": ["Sean McGinnis"], "desc": "Join Esri to see how location intelligence can revolutionize your data strategy and give your organization a competitive edge. Esri's ArcGIS technology brings interactive mapping and advanced location-based analytics to Microsoft Fabric. Discover real-world success stories and learn how organizations are using location intelligence to uncover patterns, predict trends, and make smarter decisions.", "u": "https://fabriccon.com/program/agenda?session=1081475", "tags": ["Data Science", "Data Integration"]}, {"t": "Building a Zero-Copy Enterprise Data Platform for CITGO", "d": "2026-03-19", "s": "01:00 PM", "e": "01:20 PM", "tr": "Data Engineering, Admin & Governance", "ty": "Session", "l": "200", "sp": ["Hemanth Gaddale", "Siva Pamarti"], "desc": "Can enterprises enable advanced analytics on a self-servicing platform without compromising governance? In this session, we’ll share how LevelShift redesigned CITGO’s data platform on Microsoft Fabric balancing control and autonomy. Using domain-based workspaces, OneLake zero-copy access, CI/CD automation, and layered security, eliminated duplication, and scaled governed self-service.", "u": "https://fabriccon.com/program/agenda?session=1111226", "tags": ["Data Engineering", "Admin & Governance"]}, {"t": "From Dashboard to Executive Business Reviews in Seconds", "d": "2026-03-19", "s": "01:30 PM", "e": "01:50 PM", "tr": "Data Dev, Data Engineering, Data Integration, Power BI, Admin & Governance", "ty": "Session", "l": "200", "sp": ["Younes Jallouli", "Kelly Welch"], "desc": "Discover how data leaders at companies like Equality Health, Tripadvisor, and T. Rowe Price automatically create thousands of executive and client ready slide decks. This session will teach you how to programmatically generate and update PowerPoint and Google Slides directly from your Power BI data—ensuring your stakeholders and customers get reports in the slide format they need, all while eliminating extra work and governance risk for your data team.\n\nYou’ll learn to:\n-Automate recurring reports (QBRs, Client Updates, Financial Decks).\n-Keep your slides in perfect sync with your semantic models.\n-Instantly generate hundreds of personalized deck variations (e.g., one unique deck per region or client) from a single Power BI report.", "u": "https://fabriccon.com/program/agenda?session=1127593", "tags": ["Data Engineering", "Data Dev", "Power BI", "Data Integration", "Admin & Governance"]}, {"t": "Enterprise Write-back: Driving Data-Driven Transformation with Power BI", "d": "2026-03-19", "s": "01:30 PM", "e": "01:50 PM", "tr": "Power BI", "ty": "Session", "l": "100", "sp": ["Eric Reyhle"], "desc": "Ready to see how modern planning is being redefined? Acterys showcases how a leading manufacturer moved from fragmented, Excel-based planning to streamlined, data-driven decision-making. Discover how Enterprise Write-Back in Power BI enables faster processes, greater accuracy, and efficiency—plus a live demo of the architecture, workflows, and best practices behind the transformation.", "u": "https://fabriccon.com/program/agenda?session=1124562", "tags": ["Power BI"]}, {"t": "How Impetus LeapLogic Automates the Move from Legacy Systems to Microsoft Fabric", "d": "2026-03-19", "s": "01:30 PM", "e": "01:50 PM", "tr": "Data Engineering, Admin & Governance", "ty": "Session", "l": "200", "sp": ["Michael Lass"], "desc": "Discover how Impetus LeapLogic helps teams embrace Microsoft Fabric’s unified, AI-driven architecture with speed and confidence. Join Impetus session to see up to 95% automated conversion of SQL, ETL, and BI logic—plus optimization, lineage, and validation mapped to Fabric-native patterns. Learn proven migration strategies, governance insights, and faster onboarding for Copilot-powered analytics.", "u": "https://fabriccon.com/program/agenda?session=1103985", "tags": ["Data Engineering", "Admin & Governance"]}, {"t": "SQL vs. Fabric? Why Not Both! A Practical and Entertaining Guide for All", "d": "2026-03-19", "s": "02:00 PM", "e": "03:00 PM", "tr": "SQL in Fabric, SQLCON, SQL Server", "ty": "Session", "l": "300", "sp": ["Bob Ward", "Patrick LeBlanc"], "desc": "Do you have to be experts like Bob Ward and Anna Hoffman to use SQL? What about Fabric? Do you have to know everything the Guy in a Cube knows to take advantage the power of Fabric? Why not both? Come join Bob, Patrick, and friends from Microsoft in this entertaining and educational session where the worlds of SQL and Fabric come to together in way you never knew existed.", "u": "https://fabriccon.com/program/agenda?session=1089773", "tags": ["SQLCON", "SQL Server", "SQL in Fabric"]}, {"t": "Expert vs. AI: The Power BI Turing Test", "d": "2026-03-19", "s": "02:00 PM", "e": "03:00 PM", "tr": "Power BI", "ty": "Session", "l": "200", "sp": ["Sujata Narayana", "Sid Vemuri"], "desc": "Come witness a Power BI showdown between an expert developer vs. intermediate developer supercharged by AI. Both tackle real-world challenges like designing good data models and polished reports. Like a modern Turing test, you become the judge: can AI-augmented development produce solutions indistinguishable from expert craftsmanship? Or will the subtle nuances of true mastery still stand apart?", "u": "https://fabriccon.com/program/agenda?session=1083540", "tags": ["Power BI"]}, {"t": "Best Practices for Library Management with Microsoft Fabric Spark Environments", "d": "2026-03-19", "s": "02:00 PM", "e": "03:00 PM", "tr": "Data Engineering", "ty": "Session", "l": "200", "sp": ["Shuaijun Ye", "Nupur Shukla"], "desc": "Managing Python and JAR library dependencies is key to building reliable, performant, and maintainable Spark workflows. \n\nLearn how to ensure reproducibility through consistent dependency handling, use lightweight setups to accelerate development and testing, enable inline installs for ad-hoc workloads, and integrate private repositories for secure, compliant library management.", "u": "https://fabriccon.com/program/agenda?session=1075278", "tags": ["Data Engineering"]}, {"t": "Performance monitoring for SQL, from ground to cloud", "d": "2026-03-19", "s": "02:00 PM", "e": "03:00 PM", "tr": "Azure SQL, SQLCON, SQL Server", "ty": "Session", "l": "200", "sp": ["Lance Wright", "Anitha Adusumilli"], "desc": "Managing SQL performance across your environments can be complex, but it doesn’t have to be. Introducing a fully managed performance monitoring solution that provides near real-time data, scales effortlessly, and delivers actionable insights for all workloads on Azure SQL and SQL Server. You’ll see just how fast and easy it is to monitor SQL performance, without any operational overhead.", "u": "https://fabriccon.com/program/agenda?session=1089967", "tags": ["SQLCON", "Azure SQL", "SQL Server"]}, {"t": "Unify data estates across clouds and on premises with Shortcuts and Mirroring", "d": "2026-03-19", "s": "02:00 PM", "e": "03:00 PM", "tr": "Data Integration, OneLake", "ty": "Session", "l": "200", "sp": ["Maraki Ketema", "Ajay Kavuri"], "desc": "As data volumes grow, managing an organization-wide data estate is increasingly complex. This session will deep dive into the latest capabilities to unify your data in OneLake via shortcuts and mirroring. Join us to learn how to unify your data estate, streamline ingestion, and unlock new business insights using AI and analytics.", "u": "https://fabriccon.com/program/agenda?session=1073726", "tags": ["Data Integration", "OneLake"]}, {"t": "SQL Server in Azure Virtual Machine: Configuring for price-performance", "d": "2026-03-19", "s": "02:00 PM", "e": "03:00 PM", "tr": "Azure SQL, SQLCON, Admin & Governance", "ty": "Session", "l": "300", "sp": ["David Pless"], "desc": "When selecting a virtual machine to host your SQL Server workload in Azure, you need to choose a VM size that provides optimal performance and fits your organization’s budget. \n\nIn this session, we will cover topics such as the different VM types that are appropriate for SQL workloads, configuring storage, and features unique to Azure that can help boost your performance without breaking the bank.", "u": "https://fabriccon.com/program/agenda?session=1087953", "tags": ["SQLCON", "Azure SQL", "Admin & Governance"]}, {"t": "SQL + AI: Building Agentic Apps with SQL MCP Server + Microsoft Foundry", "d": "2026-03-19", "s": "02:00 PM", "e": "03:00 PM", "tr": "SQL Server, SQLCON, Azure SQL", "ty": "Session", "l": "300", "sp": ["Davide Mauri"], "desc": "Future applications will combine intuitive UI with powerful AI interactions, enabling AI agents to on our behalf for the best experience. At the heart of this transformation is AI Foundry. In this session, we’ll explore how to integrate AI Foundry with Azure SQL, from architecture deep dive through security considerations, to give you the best knowledge to bring your solutions to the next level.", "u": "https://fabriccon.com/program/agenda?session=1092358", "tags": ["SQL Server", "Azure SQL", "SQLCON"]}, {"t": "Enterprise security in OneLake: fine-grained access control with OneLake security", "d": "2026-03-19", "s": "02:00 PM", "e": "03:00 PM", "tr": "OneLake, Admin & Governance", "ty": "Session", "l": "300", "sp": ["Aaron Merrill", "Cristian Petculescu"], "desc": "Deep dive into OneLake security including new features and how it fits in the overall Fabric security stack to get a comprehensive look at how OneLake is built to keep your data secure.", "u": "https://fabriccon.com/program/agenda?session=1063657", "tags": ["Admin & Governance", "OneLake"]}, {"t": "Connect Your Data with Graph: Why Relationships Matter for AI", "d": "2026-03-19", "s": "02:00 PM", "e": "03:00 PM", "tr": "Real-Time Intelligence, Fabric IQ, Data Engineering", "ty": "Session", "l": "200", "sp": ["Igal Amster", "Justin Fine"], "desc": "AI makes poor business decisions when it can't see how things connect - customers to orders, assets to events, signals to root causes. Graph captures these relationships and lets you explore them with natural language, no queries needed. See how Graph surfaces hidden patterns and enriches AI reasoning. Learn to model entity relationships, query connections using natural language, and turn complex data into clear, actionable insights for your AI agents.", "u": "https://fabriccon.com/program/agenda?session=1094315", "tags": ["Data Engineering", "Real-Time Intelligence", "Fabric IQ"]}, {"t": "Leveraging Governance inside your Microsoft Fabric Tenant and Workspace", "d": "2026-03-19", "s": "02:00 PM", "e": "03:00 PM", "tr": "Admin & Governance, Microsoft Purview", "ty": "Session", "l": "200", "sp": ["Martin Catherall", "Heidi Hasting"], "desc": "Microsoft Fabric's tenant and workspace settings are powerful governance tools often used in isolation. Discover overlooked Microsoft Fabric settings that collectively create a robust governance solution. Learn how to implement a strong data mesh architecture enabling business departments to self-manage governance and minimize IT dependencies. See live demonstrations of these powerful features.", "u": "https://fabriccon.com/program/agenda?session=1078194", "tags": ["Admin & Governance", "Microsoft Purview"]}, {"t": "Fabric Under the Hood: Performance-Driven Architecture for Data Warehouse & Lakehouse SQL", "d": "2026-03-19", "s": "02:00 PM", "e": "03:00 PM", "tr": "Data Warehousing", "ty": "Session", "l": "300", "sp": ["Emily Tehrani", "Peri Rocha"], "desc": "Discover the powerhouse engine behind Fabric Data Warehouse and Lakehouse SQL Analytics Endpoint. We’ll trace the query journey from optimization to execution, unpack design patterns that deliver high-performance analytics, and spotlight both recent and upcoming enhancements to continue delivering fast and scalable analytics. Perfect for those who want actionable, performance-first guidance.", "u": "https://fabriccon.com/program/agenda?session=1086271", "tags": ["Data Warehousing"]}, {"t": "Powering Data with AI Functions in Fabric", "d": "2026-03-19", "s": "02:00 PM", "e": "03:00 PM", "tr": "Data Science", "ty": "Session", "l": "300", "sp": ["Virginia Roman", "Rana Singh"], "desc": "Explore how AI functions in Microsoft Fabric can enhance the way you work with data. In this session, we’ll share the latest updates, highlight new capabilities, and walk through practical examples that demonstrate how AI functions can enrich datasets, surface insights, and streamline workflows.", "u": "https://fabriccon.com/program/agenda?session=1045849", "tags": ["Data Science"]}, {"t": "Sharing Experiences: Unlocking More Value from Power BI with Microsoft Fabric", "d": "2026-03-19", "s": "02:00 PM", "e": "03:00 PM", "tr": "Power BI", "ty": "Customer Story", "l": "100", "sp": ["Shubhangi Lal", "Joy Mediratta"], "desc": "In this session, customers will share their journeys of enhancing Power BI with Microsoft Fabric. Hear how organizations unified their data estates, streamlined analytics, and uncovered deeper insights by leveraging Fabric’s integrated platform. These real world stories highlight best practices, challenges overcome, and the tangible business value achieved when Power BI is powered by Fabric at scale.", "u": "https://fabriccon.com/program/agenda?session=1095269", "tags": ["Power BI"]}, {"t": "Govern, manage, and protect your data in Microsoft Fabric", "d": "2026-03-19", "s": "02:00 PM", "e": "03:00 PM", "tr": "Admin & Governance", "ty": "Session", "l": "200", "sp": ["Yaron Canari", "Iqbal Khan"], "desc": "Learn how you can govern and protect your data at every step of its journey with powerful, built-in tools in Fabric. Plus, see how Fabric integrates with other industry-leading governance and security solutions like Microsoft Purview for estate-wide and advanced capabilities.", "u": "https://fabriccon.com/program/agenda?session=1020096", "tags": ["Admin & Governance"]}, {"t": "Fabric IQ + Foundry IQ: Unifying data and knowledge for agentic AI", "d": "2026-03-19", "s": "02:00 PM", "e": "03:00 PM", "tr": "Microsoft Foundry, Fabric IQ, Real-Time Intelligence", "ty": "Session", "l": "200", "sp": ["Farzad Sunavala", "Chafia Aouissi"], "desc": "Join Microsoft experts for a strategic look at Fabric IQ and Foundry IQ—how they bring business meaning to data and unify enterprise knowledge to ground every agent. See roadmap updates across semantic modeling, multi‑source retrieval, governance, and observability that move you beyond basic RAG to trustworthy, scalable agentic workflows.", "u": "https://fabriccon.com/program/agenda?session=1089904", "tags": ["Microsoft Foundry", "Real-Time Intelligence", "Fabric IQ"]}, {"t": "Implementation Patterns for Fabric Real Time Intelligence", "d": "2026-03-19", "s": "02:00 PM", "e": "03:00 PM", "tr": "Real-Time Intelligence", "ty": "Session", "l": "300", "sp": ["Christopher Schmidt", "Subbu Muthukrishnan"], "desc": "Learn how organizations transform streaming data into immediate action. We'll explore real-world patterns for ingesting IoT, PoS and enterprise events to enable predictive actions and automated responses. Discover architectural approaches for processing events at scale, combining real-time data with historical analytics, and build solutions that deliver measurable business impact across industries", "u": "https://fabriccon.com/program/agenda?session=1072657", "tags": ["Real-Time Intelligence"]}, {"t": "Fabric Extensibility Toolkit: Build your own Fabric item in minutes with AI", "d": "2026-03-19", "s": "02:00 PM", "e": "03:00 PM", "tr": "Data Dev", "ty": "Session", "l": "300", "sp": ["Gerd Saurer", "Zoe Abboudi"], "desc": "In this session, we'll show how any developer can use the Fabric Extensibility Toolkit, an evolution of the Workload Development Kit, to bring thier own data applications into Fabric within minutes. We'll also highlight how the Toolkit has been redesigned with a simplified architecture and AI to drastically streamline development.", "u": "https://fabriccon.com/program/agenda?session=1040858", "tags": ["Data Dev"]}, {"t": "Fabric Development: Repos, Collaboration and Deployments", "d": "2026-03-19", "s": "02:00 PM", "e": "03:00 PM", "tr": "Data Engineering, Developer Experiences", "ty": "Session", "l": "300", "sp": ["Mike Diehl"], "desc": "Are you a Fabric developer and struggling with using good development practices? \nImplementing practices such as source code control, branching strategies, code reviews (PRs), and automated deployments to independent environments (ie. workspaces) can transform how you work with Fabric. \nWe'll show how to implement them and work around the gotchas that will bite you in your Fabric projects.", "u": "https://fabriccon.com/program/agenda?session=1079780", "tags": ["Developer Experiences", "Data Engineering"]}, {"t": "How Health Systems Can Join the EMR Cloud Journey", "d": "2026-03-19", "s": "02:00 PM", "e": "03:00 PM", "tr": "Data Warehousing, Power BI", "ty": "Session", "l": "100", "sp": ["Jamie McGlothlin", "Daniella Herskowitz"], "desc": "Major electronic medical records (EMRs) including Epic are transitioning their data offerings to Fabric.    This session will investigate how to integrate this data with client data and platforms.  We will describe the journey of Corewell Health including Cogito Cloud, a clinical Fabric instance, bi-directional shortcuts, Snowflake integration, and AI-enabled migration to PowerBi.", "u": "https://fabriccon.com/program/agenda?session=1081186", "tags": ["Power BI", "Data Warehousing"]}, {"t": "The Golden Thread: Architecting an End-to-End OneLake Fabric for Analytics, RTI, and RAG", "d": "2026-03-19", "s": "02:00 PM", "e": "03:00 PM", "tr": "Data Engineering, Microsoft Foundry", "ty": "Session", "l": "300", "sp": ["Loy Sikdar"], "desc": "The Golden Thread, a unified OneLake-driven Microsoft Fabric architecture for analytics, predictive intelligence, and retrieval augmented generation (RAG). Learn how to evolve from siloed analytics to a scalable Medallion ecosystem with metadata-driven orchestration, hybrid CI/CD, and integrated real-time + historical data flows. We’ll also walk through a predictive maintenance scenario that demonstrates how to modernize workloads and accelerate insight delivery across any industry.", "u": "https://fabriccon.com/program/agenda?session=1110828", "tags": ["Microsoft Foundry", "Data Engineering"]}, {"t": "Fabric IQ + Agent 365: Identity, Governance & Tooling for Microsoft Fabric", "d": "2026-03-19", "s": "02:00 PM", "e": "03:00 PM", "tr": "Power Platform, Fabric IQ, Admin & Governance", "ty": "Session", "l": "300", "sp": ["Rohith Sai Chetla", "Adam Lash"], "desc": "Discover how Agent 365 serves as the enterprise control plane for AI in Microsoft Fabric, anchored on five pillars: registry, control, visualize, interop, and security for Fabric assets consumed by agents. Learn how Entra identity, Purview governance, and Agent 365 tools enable governed deployments, reference architectures, and safe scale for IT pros, developers, and data engineers.", "u": "https://fabriccon.com/program/agenda?session=1088279", "tags": ["Power Platform", "Admin & Governance", "Fabric IQ"]}, {"t": "Fabric Partner Team: Ask Me Anything", "d": "2026-03-19", "s": "03:00 PM", "e": "04:00 PM", "tr": "No Track", "ty": "AMA", "l": "", "sp": ["Fabric Partner Team"], "desc": "Let’s talk partnership! We’re hosting an AMA with the Fabric Partner Success Team, and you’re invited. Whether you’re just getting started or looking to scale your Fabric practice, this is your chance to ask questions, get advice, and connect with the team supporting partner success. Don’t miss this opportunity to learn, share, and grow—see you there!", "u": "https://fabriccon.com/program/agenda?session=1139841", "tags": ["No Track"]}, {"t": "Autonomous AI Agents in Production: Komatsu with CluedIn, Fabric & Purview", "d": "2026-03-19", "s": "03:20 PM", "e": "03:40 PM", "tr": "Data Engineering, Admin & Governance", "ty": "Session", "l": "300", "sp": ["Tim Ward"], "desc": "This session presents Komatsu’s production deployment of autonomous AI agents over a governed Microsoft Fabric estate integrated with Purview and CluedIn. We cover the architecture, agent execution model and parallelism, governance and audit controls, and concrete lessons learned from operating agents at 3–10M records/day, including failure modes and rule-performance tuning.", "u": "https://fabriccon.com/program/agenda?session=1111812", "tags": ["Data Engineering", "Admin & Governance"]}, {"t": "Scaling Fabric Write Back for Real-Time Collaboration & Data Enrichment", "d": "2026-03-19", "s": "03:20 PM", "e": "03:40 PM", "tr": "Power BI, SQL in Fabric, Power Platform", "ty": "Session", "l": "200", "sp": ["Marija Zutic", "Josh Warbington"], "desc": "Fabric's native writeback excels at single-record forms, but teams often need to enrich multiple data points, add context across records, or collaborate in real-time. Learn how to extend Fabric's writeback from forms to Excel-like tabular editing that scales. Walk away understanding how to transform your Fabric environment into an active, collaborative decision-making platform.", "u": "https://fabriccon.com/program/agenda?session=1121672", "tags": ["Power BI", "Power Platform", "SQL in Fabric"]}, {"t": "What Microsoft Fabric Looks Like with End-to-End Automation", "d": "2026-03-19", "s": "03:20 PM", "e": "03:40 PM", "tr": "Data Engineering, Data Warehousing, Data Integration", "ty": "Session", "l": "300", "sp": ["Endika Pascual"], "desc": "Production-grade Microsoft Fabric implementations require coordinated ingestion, data refinement, warehouse operations, and governance. This session examines how Data Factory pipelines, OneLake Medallion architecture, and Fabric Warehouses work together in automated platforms, focusing on orchestration and warehouse automation patterns for reliable, repeatable analytics.", "u": "https://fabriccon.com/program/agenda?session=1115223", "tags": ["Data Engineering", "Data Integration", "Data Warehousing"]}, {"t": "Microsoft Fabric Security: Best Practices for Network, Data and Governance", "d": "2026-03-19", "s": "04:15 PM", "e": "05:15 PM", "tr": "Admin & Governance, Microsoft Purview", "ty": "Session", "l": "300", "sp": ["Vengatesh Parasuraman", "Amanjeet Singh"], "desc": "Security is foundational in Microsoft Fabric. While Fabric offers defense-in-depth by default, enterprises need clear practices to align with organizational policies. This session provides end-to-end best practices and patterns for securing Fabric through inbound controls, outbound protections, RBAC for workspaces, OneLake security, customer-managed keys, and data governance with Purview.", "u": "https://fabriccon.com/program/agenda?session=1087896", "tags": ["Admin & Governance", "Microsoft Purview"]}, {"t": "What's new in Mirroring SQL to Fabric: The Fast Track to Modern Data Integration & Analytics", "d": "2026-03-19", "s": "04:15 PM", "e": "05:15 PM", "tr": "Azure SQL, SQLCON, SQL Server", "ty": "Session", "l": "300", "sp": ["Idris Motiwala", "Ajay Jagannathan"], "desc": "As organizations navigate the era of generative AI, advanced analytics, and rapid digital transformation, the ability to extract timely business insights is more critical than ever. This session deep dives into SQL Mirroring in Microsoft Fabric that enables organizations with near real-time data replication from source SQL databases to OneLake, all without building intricate ETL processes.", "u": "https://fabriccon.com/program/agenda?session=1089837", "tags": ["SQLCON", "Azure SQL", "SQL Server"]}, {"t": "Unlocking T-SQL Surface Area in Microsoft Fabric: Where It Works, Where It Doesn’t and Why", "d": "2026-03-19", "s": "04:15 PM", "e": "05:15 PM", "tr": "Data Warehousing, SQL in Fabric", "ty": "Session", "l": "300", "sp": ["Jared Kuehn"], "desc": "Microsoft Fabric relational engines support T-SQL, but not always the same way. Why? This session explains SQL surface area, explores Fabric's engines (warehouses, databases, endpoints, etc.), and shows where T-SQL works - Helping you design smarter with supported features and architecture in mind.", "u": "https://fabriccon.com/program/agenda?session=1048408", "tags": ["Data Warehousing", "SQL in Fabric"]}, {"t": "What's new in the SQL core engine - the 2026 edition", "d": "2026-03-19", "s": "04:15 PM", "e": "05:15 PM", "tr": "SQL Server, SQLCON, Azure SQL", "ty": "Session", "l": "300", "sp": ["Dimitri Furman", "Derek Wilson"], "desc": "With all the news about developer and AI features in SQL, you might wonder if we had any time to invest in the RDBMS core. We certainly did! If you are a DBA, a data engineer, or a developer interested in the new performance and reliability features in query processing and all the way down into the storage engine, join us to learn what's new. We guarantee you'll walk away with new ideas!", "u": "https://fabriccon.com/program/agenda?session=1091231", "tags": ["SQL Server", "Azure SQL", "SQLCON"]}, {"t": "Simplify Geospatial Analytics with Maps in Fabric", "d": "2026-03-19", "s": "04:15 PM", "e": "05:15 PM", "tr": "Real-Time Intelligence", "ty": "Session", "l": "200", "sp": ["Johannes Kebeck", "Andre Terceros"], "desc": "Geospatial analytics traditionally requires specialized tools and expertise, creating barriers for teams that need location-based insights. Real-Time Intelligence in Fabric changes this by bringing \"living maps\" to everyone. Explore how to work with high-velocity, large-volume geospatial data from ingestion and processing to visualization and actions. Learn to create real-time map visualizations, process location data, and provide spatial context for your users and AI agents.", "u": "https://fabriccon.com/program/agenda?session=1094445", "tags": ["Real-Time Intelligence"]}, {"t": "Master Eventhouse Patterns for Real-Time Intelligence at Scale", "d": "2026-03-19", "s": "04:15 PM", "e": "05:15 PM", "tr": "Real-Time Intelligence, Data Science", "ty": "Session", "l": "300", "sp": ["Christopher Schmidt", "Brad Watts"], "desc": "Processing millions of events while maintaining historical context and automating decisions is one of the hardest challenges in enterprise data. Eventhouse and Real-Time Intelligence solve this with proven patterns used in production today. See how organizations process events at scale, automate decisions, and combine real-time and historical data for business operations. Learn the architectures powering AI and analytics in production and patterns you can apply immediately.", "u": "https://fabriccon.com/program/agenda?session=1081361", "tags": ["Data Science", "Real-Time Intelligence"]}, {"t": "Interoperable by design: managing Iceberg and Delta Tables in OneLake", "d": "2026-03-19", "s": "04:15 PM", "e": "05:15 PM", "tr": "OneLake, OneLake", "ty": "Session", "l": "300", "sp": ["Kevin Liu", "Matt Hicks"], "desc": "OneLake enables true interoperability, enabling you to write Iceberg and Delta tables once and query them anywhere. Learn how OneLake supports data governance, Spark DML and lifecycle management while exposing the same tables to Snowflake, Athena, Glue, Fabric engines, Power BI, and AI Agents without copies.", "u": "https://fabriccon.com/program/agenda?session=1042365", "tags": ["OneLake"]}, {"t": "Microsoft Purview Data Security protections in the Age of AI", "d": "2026-03-19", "s": "04:15 PM", "e": "05:15 PM", "tr": "Microsoft Purview, Admin & Governance", "ty": "Session", "l": "300", "sp": ["Darren Portillo", "Anton Fritz"], "desc": "Learn how Microsoft Purview Data Security helps you discover risks and protect data consistently across your entire estate, with a focus on your Fabric estate. This session will introduce newer innovations and cover capabilities such as Information Protection, Data Loss Prevention and Data Security Posture Management.", "u": "https://fabriccon.com/program/agenda?session=1092870", "tags": ["Admin & Governance", "Microsoft Purview"]}, {"t": "The AI-Native Data Engineer", "d": "2026-03-19", "s": "04:15 PM", "e": "05:15 PM", "tr": "Data Engineering, Developer Experiences", "ty": "Session", "l": "200", "sp": ["Deepa Rajagopal", "Piero Morano"], "desc": "This session explores how AI is transforming data engineering. We’ll walk through the latest AI innovations in Microsoft Fabric including AI‑powered notebooks, deep Copilot integration in VS Code, and CLI workflow. We will explore how these capabilities are changing how data engineers build, iterate, and operate day to day. Discover how agentic Copilot across Fabric Web, VS Code, and CLI removes coding barriers, accelerates time to value and automates repetitive tasks, leaving engineers to focus on higher-order problems.", "u": "https://fabriccon.com/program/agenda?session=1087702", "tags": ["Developer Experiences", "Data Engineering"]}, {"t": "Ignite Governance Insights Across Databases, Lakes, and Models", "d": "2026-03-19", "s": "04:15 PM", "e": "05:15 PM", "tr": "Azure SQL, SQLCON, Data Warehousing", "ty": "Session", "l": "200", "sp": ["Karen Lopez"], "desc": "Turn data governance into a productivity boost for Azure SQL Database, Fabric SQL Database, and Fabric Data Warehouse architectures and engineering. Gain efficiency and confidence in every deployment. Learn how cataloging, classification, lineage, and quality workflows integrate with databases and pipelines to improve trust, and enable secure, compliant data for engineering teams.", "u": "https://fabriccon.com/program/agenda?session=1072440", "tags": ["SQLCON", "Azure SQL", "Data Warehousing"]}, {"t": "Own Your Workflow: Build Notebooks Locally & Deploy Them to Fabric", "d": "2026-03-19", "s": "04:15 PM", "e": "05:15 PM", "tr": "Data Engineering, Data Science", "ty": "Session", "l": "300", "sp": ["Andy Parkerson"], "desc": "Break free from browser IDE in Fabric Python and PySpark Notebooks! Learn to install Python and Spark, create your own local lakehouse, and develop Python and PySpark Notebooks in Visual Studio, VSCode, or whatever IDE you're used to. We'll start with a clean machine and download, install and configure everything we need. We will create a feature-rich notebook, and wrap up by deploying to Fabric.", "u": "https://fabriccon.com/program/agenda?session=1081094", "tags": ["Data Science", "Data Engineering"]}, {"t": "Building an AutoML Pipeline for Vector Data in Azure SQL", "d": "2026-03-19", "s": "04:15 PM", "e": "05:15 PM", "tr": "Azure SQL, SQLCON, Microsoft Foundry", "ty": "Session", "l": "300", "sp": ["Omer Colakoglu"], "desc": "This session demonstrates how to build an AutoML-driven pipeline inside Azure SQL to process and optimize vector data. Learn how to automatically profile datasets, select the best embedding model and parameters, and improve retrieval accuracy using adaptive evaluation and feedback loops.", "u": "https://fabriccon.com/program/agenda?session=1080694", "tags": ["SQLCON", "Azure SQL", "Microsoft Foundry"]}, {"t": "Agentic Data Engineering on Microsoft Fabric: Building Adaptive Pipelines", "d": "2026-03-19", "s": "04:15 PM", "e": "05:15 PM", "tr": "Data Engineering, Data Integration, Fabric IQ", "ty": "Session", "l": "100", "sp": ["Nina Arora-Rowland", "Colin Pop", "Mittul Mehta"], "desc": "What happens when data engineering meets agentic AI? In this technical session, we explore how autonomous agents are reshaping the way pipelines are built, managed, and evolved on Microsoft Fabric. From real-world scenarios to emerging architectural patterns, we’ll examine how intelligent systems can move data operations beyond static scripts toward adaptive, context-aware workflows. We’ll also address practical considerations around governance, trust, and enterprise readiness as teams experiment with more autonomous data environments. Join us to unpack what it takes to move from traditional pipelines to intelligent, evolving data systems.", "u": "https://fabriccon.com/program/agenda?session=1104869", "tags": ["Data Engineering", "Data Integration", "Fabric IQ"]}, {"t": "Azure Readiness for Fabric: What Every Organization Needs to Know", "d": "2026-03-19", "s": "04:15 PM", "e": "05:15 PM", "tr": "Admin & Governance", "ty": "Session", "l": "200", "sp": ["Scott Cameron"], "desc": "Adopting Microsoft Fabric with minimal Azure experience? Discover the essentials of Azure Readiness for Fabric: security, performance, manageability, and extensibility so your organization can deploy Fabric confidently and be ready for future Azure growth. Practical guidance for teams starting their Fabric journey, especially if you are new to Azure or migrating from Power BI Premium to Fabric.", "u": "https://fabriccon.com/program/agenda?session=1080388", "tags": ["Admin & Governance"]}, {"t": "DAX 201: CALCULATE, Unfolding the Swiss Army Knife of DAX Functions", "d": "2026-03-19", "s": "04:15 PM", "e": "05:15 PM", "tr": "Power BI", "ty": "Session", "l": "200", "sp": ["Michael Hewitt"], "desc": "This session unfolds evaluation context and the logic behind CALCULATE(). Through examples, we'll demystify how row context, filter context, and CALCULATE() work together to produce dynamic calculation results. You'll gain confidence to tackle advanced calculations and optimize measure performance.", "u": "https://fabriccon.com/program/agenda?session=1065890", "tags": ["Power BI"]}, {"t": "Talking about mental health - For you and for them", "d": "2026-03-19", "s": "04:15 PM", "e": "05:15 PM", "tr": "Diversity, Equity & Inclusion", "ty": "Session", "l": "100", "sp": ["Traci Sewell"], "desc": "Looking after more than just 1's and 0's is important for us all.\n\nEveryone experiences, or is adjacent to people who experience, challenges with mental health. In both the workplace and personal life, it can feel very difficult to talk with people about these challenges.", "u": "https://fabriccon.com/program/agenda?session=1065712", "tags": ["Diversity", "Equity & Inclusion"]}, {"t": "The Agentic Data Estate - Make, Manage, Monitor", "d": "2026-03-19", "s": "04:15 PM", "e": "05:15 PM", "tr": "Microsoft Foundry, Data Integration", "ty": "Session", "l": "200", "sp": ["Tom Eastlake", "Jason Miles"], "desc": "Learn how digital workers, supported by the Agent Framework and digital workforce management best practices, can run your Fabric data estate.   Discovery, Observability, Continuous Optimization, Quality & Drift are just some of the key workloads that can be automated using agents.  \n\nSee how you can identify and implement the digital worker roles which make the most sense for your enterprise.", "u": "https://fabriccon.com/program/agenda?session=1081145", "tags": ["Microsoft Foundry", "Data Integration"]}, {"t": "SQL Database in Fabric: Modern Operational & Analytical Apps at Scale", "d": "2026-03-19", "s": "04:15 PM", "e": "05:15 PM", "tr": "SQL in Fabric, SQLCON, Data Dev", "ty": "Session", "l": "300", "sp": ["Anupama Natarajan"], "desc": "Explore how SQL database in Fabric powers modern operational and analytical workloads in a single platform. Through a global automotive dealership network, learn how inventory, service records, test-drive logs, and customer activity are unified into Fabric to build high-performance apps, real-time insights, and AI-assisted analytics.", "u": "https://fabriccon.com/program/agenda?session=1080129", "tags": ["SQLCON", "Data Dev", "SQL in Fabric"]}, {"t": "From Zero to Launch: Talcott’s New Retail Annuity Business platform powered by Microsoft Fabric", "d": "2026-03-19", "s": "04:15 PM", "e": "05:15 PM", "tr": "OneLake, Data Engineering", "ty": "Session", "l": "200", "sp": ["Ed Bobrin", "Ashwin Sanal Kumar", "Aravind Viswanathan", "Prasad Waigankar"], "desc": "Join EY’s Global Fabric Tech Hub for a moderated fireside chat with Talcott on how they launched a new retail annuity business on Microsoft Fabric. We’ll unpack the end-to-end journey—why Fabric, how the architecture came together (OneLake, Data Factory, Data Engineering, Data Warehouse, Power BI), and the outcomes: accelerated market entry, automation driven efficiency, and real time decisioning. We’ll also discuss what’s repeatable for other enterprises and where to start, including Fabric IQ, governance, adoption, and how Real Time Intelligence fits.", "u": "https://fabriccon.com/program/agenda?session=1080828", "tags": ["Data Engineering", "OneLake"]}, {"t": "Make your Power BI Desktop report print-ready (in one hour or less)", "d": "2026-03-19", "s": "04:15 PM", "e": "05:15 PM", "tr": "Power BI", "ty": "Session", "l": "300", "sp": ["Lenore Flower"], "desc": "Need a printable version of an existing Power BI report fast? Learn how to convert a .pbix into a paginated .rdl by using the same semantic model in Power BI Report Builder. This session walks you through each step of converting an existing Power BI report into its paginated equivalent, then reviews how to address common paginated report issues with parameters, print layout, and grouping.", "u": "https://fabriccon.com/program/agenda?session=1081598", "tags": ["Power BI"]}, {"t": "Power Hour", "d": "2026-03-19", "s": "05:30 PM", "e": "07:00 PM", "tr": "No Track", "ty": "Social Event", "l": "", "sp": ["Microsoft Product Team"], "desc": "Nothing will prepare you for this fast-paced, borderline ridiculous community event!  Join us for Power Hour, a live-demo driven session that you can't afford to miss. This unique session brings together members of the Microsoft product team and members of the data community to use Microsoft Fabric, Power BI and SQL Server tools in ways never intended.  If you learn something during Power Hour, you're doing it wrong!", "u": "https://fabriccon.com/program/agenda?session=1132935", "tags": ["No Track"]}, {"t": "Intelligent analytics in real-world scenarios", "d": "2026-03-20", "s": "08:00 AM", "e": "09:00 AM", "tr": "Power BI, Microsoft Foundry", "ty": "Session", "l": "200", "sp": ["Monica Calleja", "Sara Lammini Rodriguez"], "desc": "In today’s AI-driven world, the integration of data, analytics tools, and AI agents is more critical than ever. This session focuses on how AI agents, Power BI, and other Fabric capabilities can be integrated to implement a real-world solution. We will demonstrate how to ingest and process data, train and deploy predictive models, create conversational experiences, and perform intelligent analytics to address a common business challenge. Join us to explore how these technologies work together to deliver impactful, production-ready solutions.", "u": "https://fabriccon.com/program/agenda?session=1083396", "tags": ["Power BI", "Microsoft Foundry"]}, {"t": "SAP, Oracle, Google BigQuery, Dataverse - Unify the business data estate with OneLake", "d": "2026-03-20", "s": "08:00 AM", "e": "09:00 AM", "tr": "Data Integration, OneLake", "ty": "Session", "l": "200", "sp": ["Wilson Lee", "Matt Hicks"], "desc": "Join us to see how Microsoft Fabric and OneLake unify your business data estate with petabyte-scale data movement and Mirroring. Discover best practices for copying, replicating, and virtualizing data from SAP, Oracle, Google BigQuery, Dataverse, and more—leveraging enterprise proven patterns to accelerate analytics and unlock actionable insights.", "u": "https://fabriccon.com/program/agenda?session=1077681", "tags": ["Data Integration", "OneLake"]}, {"t": "Hardening Fabric Warehouse Security", "d": "2026-03-20", "s": "08:00 AM", "e": "09:00 AM", "tr": "Data Warehousing, Admin & Governance", "ty": "Session", "l": "300", "sp": ["Freddie Santos", "Sam Debruyn"], "desc": "Learn how to secure Fabric Data Warehouse from the ground up. This session covers end-to-end practices—from secure connectivity and authentication to auditing, monitoring, and governance—highlighting new features that strengthen compliance, visibility, and trust at scale.", "u": "https://fabriccon.com/program/agenda?session=1019005", "tags": ["Admin & Governance", "Data Warehousing"]}, {"t": "Hyperscale - the SQL Database for All Workloads", "d": "2026-03-20", "s": "08:00 AM", "e": "09:00 AM", "tr": "Azure SQL, SQLCON", "ty": "Session", "l": "200", "sp": ["Jes Chapman"], "desc": "See how organizations are adopting Azure SQL Database Hyperscale for new and growing workloads. We’ll walk through real implementations—including scaling from zero to hundreds of databases— to learn what DBAs and devs learned along the way, and show demos of the tools and features that made those deployments successful.", "u": "https://fabriccon.com/program/agenda?session=1080507", "tags": ["SQLCON", "Azure SQL"]}, {"t": "SQL database in Fabric: The Fast Path to Modern, Scalable Analytics", "d": "2026-03-20", "s": "08:00 AM", "e": "09:00 AM", "tr": "SQL in Fabric, SQLCON, Data Engineering", "ty": "Session", "l": "100", "sp": ["Chris Wagner"], "desc": "Learn how SQL databases deliver scalable, secure, and cost-effective analytics in Microsoft Fabric. Explore design patterns, migration strategies, and performance tuning to modernize your data platform while ensuring governance, AI readiness, and seamless Power BI integration.", "u": "https://fabriccon.com/program/agenda?session=1019824", "tags": ["SQLCON", "Data Engineering", "SQL in Fabric"]}, {"t": "The Ultimate \"NO ETL\" Show Down: Shortcuts vs Mirroring vs Copy Job", "d": "2026-03-20", "s": "08:00 AM", "e": "09:00 AM", "tr": "Data Integration", "ty": "Session", "l": "200", "sp": ["Nikola Ilic"], "desc": "No ETL - no problem! Fabric introduced several innovative features to access external data without spending time on building complex ETL. \n\nBut, which one is right for YOU? We'll examine various data movement strategies, their pros and cons, so you'll feel more confident picking the right one", "u": "https://fabriccon.com/program/agenda?session=1041280", "tags": ["Data Integration"]}, {"t": "Proven Fabric Architecture Patterns to Minimize Refactoring", "d": "2026-03-20", "s": "08:00 AM", "e": "09:00 AM", "tr": "Admin & Governance, Data Engineering", "ty": "Session", "l": "300", "sp": ["Matthias Falland"], "desc": "Expensive refactoring from poor architecture is avoidable. Discover architecture patterns from 20+ implementations: workspace topology, medallion layers, and cross-workspace sharing. Learn how these strategies minimize refactoring by 60%, accelerating time-to-production.", "u": "https://fabriccon.com/program/agenda?session=1018851", "tags": ["Data Engineering", "Admin & Governance"]}, {"t": "SQL Database in Fabric: Simplifying OLTP and Enabling Rapid Analytics", "d": "2026-03-20", "s": "08:00 AM", "e": "09:00 AM", "tr": "SQL in Fabric, SQLCON, Azure SQL", "ty": "Session", "l": "200", "sp": ["Jeff Taylor"], "desc": "New to Fabric - or just new to Databases in Fabric? See how SQL database in Fabric merges OLTP and analytics workloads into one cloud-native solution. Learn how it replicates data to OneLake, supports familiar tools, and simplifies architecture—boosting insights without added complexity.", "u": "https://fabriccon.com/program/agenda?session=1034798", "tags": ["SQLCON", "Azure SQL", "SQL in Fabric"]}, {"t": "Modern Data Protection Strategies with SQL Server", "d": "2026-03-20", "s": "08:00 AM", "e": "09:00 AM", "tr": "SQL Server, SQLCON, Admin & Governance", "ty": "Session", "l": "200", "sp": ["John Sterrett"], "desc": "Today, we handle increasing volumes of sensitive data. DBAs and Data Engineers must protect their data from external attackers, employees, and privileged admins like themselves. This session will teach you how to protect your data while maintaining functionality and performance. The session focuses on using column-level encryption, row-level security, and auditing to secure your data.", "u": "https://fabriccon.com/program/agenda?session=1081546", "tags": ["SQL Server", "Admin & Governance", "SQLCON"]}, {"t": "Sharing Experiences: Real-Time Intelligence —Customer Stories from the Frontlines of Fabric", "d": "2026-03-20", "s": "08:00 AM", "e": "09:00 AM", "tr": "Real-Time Intelligence", "ty": "Customer Story", "l": "100", "sp": ["Andrew Joncas", "Tami Mahadevan"], "desc": "In this session, we spotlight how leading organizations are transforming operations and decision-making with Microsoft Fabric’s Real-Time Intelligence capabilities. From connected factories and autonomous logistics to fraud detection and energy optimization, customers are harnessing streaming data, event-driven architectures, and AI-powered automation to act in the moment. Hear firsthand how these customers experienced their Fabric journey to reduce latency, cut operational costs, and unlock new business models. These stories go beyond technology—they reveal the strategic shifts, cultural changes, and measurable outcomes that define real-time success in the era of AI.", "u": "https://fabriccon.com/program/agenda?session=1095265", "tags": ["Real-Time Intelligence"]}, {"t": "Inside of OneLake Spark Catalog and migration to schema-enabled lakehouses", "d": "2026-03-20", "s": "08:00 AM", "e": "09:00 AM", "tr": "Data Engineering", "ty": "Session", "l": "300", "sp": ["Ted Vilutis"], "desc": "Discover the capabilities of the OneLake Spark Catalog, which supports Lakehouse schemas, cross-workspace querying, row- and column-level security, and more. Examine techniques for querying objects using Spark within Fabric, including simultaneous access to Data Warehouses, Mirror Databases, and Lakehouses. Finally, review best practices and strategies for enabling OneLake Spark Catalog for all Spark runs and migrating to schema-enabled lakehouses.", "u": "https://fabriccon.com/program/agenda?session=1020374", "tags": ["Data Engineering"]}, {"t": "Trusted Contextual Data Foundation for reliable AI outcomes", "d": "2026-03-20", "s": "08:00 AM", "e": "09:00 AM", "tr": "Microsoft Foundry, Data Engineering, Data Science, Data Warehousing, OneLake, Admin & Governance", "ty": "Session", "l": "300", "sp": ["Gopi Sankaran", "Ajay Gollapalli"], "desc": "Organizations struggle to trust their data - to contextualize and operationalize it safely for AI driven decision-making. As enterprises move beyond dashboards and reports towards agentic AI systems that reason, decide and act, the limitations of fragmented data platforms, inconsistent definitions and disconnected governance are impossible to ignore. Trusted context enabled by clean, governed and connected data is the critical ingredient in enterprise AI success.\n \nThis session highlights strategies for bringing multi-domain master data management, data quality, governance, privacy and policy enforcement, and end to end lineage to ensure that every dataset consumed by analytics, BI and AI agents is trusted, governed and ready for AI agents to reason with enterprise truth.", "u": "https://fabriccon.com/program/agenda?session=1129744", "tags": ["OneLake", "Data Warehousing", "Data Science", "Microsoft Foundry", "Data Engineering", "Admin & Governance"]}, {"t": "From Fabric to Finance: Building Enterprise-Grade Planning & Forecasting on Microsoft Fabric", "d": "2026-03-20", "s": "08:00 AM", "e": "09:00 AM", "tr": "Data Integration, Azure SQL", "ty": "Session", "l": "300", "sp": ["Alp Akdeniz", "Khaled Ahmed"], "desc": "Microsoft Fabric has fundamentally changed how enterprises store, model, and analyze data — but many organizations still struggle to turn that data into real-time operational and financial decisions.\n\nIn this session, we will explore how to design an enterprise-grade planning and forecasting architecture natively on Microsoft Fabric, using Azure SQL, Power BI, and modern data pipelines to enable real-time write-back, scenario modeling, and governed collaboration across large organizations.\n\nAttendees will learn how to:\n- Architect a Fabric-native planning environment that supports concurrent users, auditability, and data integrity\n- Design write-enabled analytical models using Azure SQL, Fabric Warehouses, and Power BI\n- Implement scenario modeling, forecasting, and what-if analysis directly on enterprise data\n- Apply governance, security, and performance best practices for mission-critical workloads\n- Avoid common pitfalls that cause Fabric-based planning solutions to fail at scale\n\nThe session will include a live technical walkthrough of how data moves from Fabric into planning and forecasting workflows, how user inputs are written back securely, and how changes propagate through enterprise-grade models in real time.\n\nWhether you are modernizing an FP&A platform, enabling operational planning, or deploying large-scale analytics on Fabric, this session will provide practical patterns and architecture that you can apply immediately inside your own Microsoft environment.", "u": "https://fabriccon.com/program/agenda?session=1124554", "tags": ["Azure SQL", "Data Integration"]}, {"t": "Building an AI-Ready Data Platform: Data Agents, Ontology, and Governance in Microsoft Fabric", "d": "2026-03-20", "s": "09:30 AM", "e": "09:50 AM", "tr": "OneLake", "ty": "Session", "l": "100", "sp": ["Hukum Chandu Rokkala", "Nir Patel"], "desc": "AI agents and Copilots are only as effective as the data platforms behind them. Learn how to build an AI-ready Frontier Data Platform using Microsoft Fabric, powered by Data Agents, shared ontology, & governance. Learn how OneLake, semantic definitions, lineage, and policy-driven access enable safe AI at scale, & how Sonata’s Lightning Data Suite accelerates readiness with prebuilt accelerators.", "u": "https://fabriccon.com/program/agenda?session=1120797", "tags": ["OneLake"]}, {"t": "From Stalled to Scaled: How Tolmar Built a Trusted Fabric Platform for Agents", "d": "2026-03-20", "s": "09:30 AM", "e": "09:50 AM", "tr": "Admin & Governance, OneLake", "ty": "Session", "l": "100", "sp": ["Carl Spitzer", "Jon Steffey"], "desc": "Enterprises are moving quickly toward Copilot and agentic AI, but most struggle to scale beyond pilots because the data foundation isn’t ready. In this session, Adastra and Tolmar share how building a reliable, governed data estate in Microsoft Fabric and OneLake is the critical first step to enabling trusted AI and enterprise agents.", "u": "https://fabriccon.com/program/agenda?session=1126083", "tags": ["Admin & Governance", "OneLake"]}, {"t": "Embedding Power Apps in Microsoft Fabric Power BI Reports", "d": "2026-03-20", "s": "10:10 AM", "e": "11:10 AM", "tr": "Power Platform, Power BI", "ty": "Session", "l": "200", "sp": ["Paul Papanek Stork", "Scott Shearer"], "desc": "In this talk we’ll show you how to embed a Power App in a Power BI report in Microsoft Fabric to enable real-time editing and interactivity. See how to update data directly from reports, trigger workflows, and leverage action-oriented analytics that close the loop between insight and execution.", "u": "https://fabriccon.com/program/agenda?session=1035028", "tags": ["Power BI", "Power Platform"]}, {"t": "SQL Server 2025 is the AI-ready Enterprise Database", "d": "2026-03-20", "s": "10:10 AM", "e": "11:10 AM", "tr": "SQL Server, SQLCON, Developer Experiences", "ty": "Session", "l": "300", "sp": ["Bob Ward", "Kendal Van Dyke"], "desc": "You may have heard the news that SQL Server 2025 has become Generally Available. But do you know why there has been so much buzz about this new version? Come learn from the team at Microsoft everything you need to know about why you should consider upgrading to SQL Server 2025. From AI to developer features to mission critical engine, SQL Server 2025 has more new features than you might realize.", "u": "https://fabriccon.com/program/agenda?session=1089237", "tags": ["SQL Server", "Developer Experiences", "SQLCON"]}, {"t": "A data lake built for scale: a deep dive into OneLake performance, APIs, and diagnostics", "d": "2026-03-20", "s": "10:10 AM", "e": "11:10 AM", "tr": "OneLake, OneLake", "ty": "Session", "l": "200", "sp": ["Elizabeth Oldag", "Tom Peplow"], "desc": "Join this session to learn how OneLake delivers a unified SaaS data lake for your Fabric tenant, simplifying governance and enabling AI-driven insight. With blob and ADLS-compatible APIs, OneLake integrates seamlessly with existing tools. Features like tiered storage, item-size reports and diagnostic logs simplify optimization, while auto-scaling ensures fast, reliable performance as demand grows.", "u": "https://fabriccon.com/program/agenda?session=1087718", "tags": ["OneLake"]}, {"t": "Build Trustworthy Real-Time AI Applications with Eventstream in Real-Time Intelligence", "d": "2026-03-20", "s": "10:10 AM", "e": "11:10 AM", "tr": "Real-Time Intelligence", "ty": "Session", "l": "200", "sp": ["Alicia Li", "Kevin Lam"], "desc": "Real-time AI is only as trustworthy as the streaming infrastructure behind it. Discover innovations in Eventstream for building secure, governed streaming architectures that feed your AI systems reliable data. Learn to ingest from VNet-isolated environments, monitor pipelines with full observability, process CDC streams at scale, and see new connectors in action.", "u": "https://fabriccon.com/program/agenda?session=1025145", "tags": ["Real-Time Intelligence"]}, {"t": "Making AI Agents Smarter with Fabric IQ and Foundry IQ", "d": "2026-03-20", "s": "10:10 AM", "e": "11:10 AM", "tr": "Microsoft Foundry, Fabric IQ, Power BI", "ty": "Session", "l": "300", "sp": ["Treb Gatte"], "desc": "Connecting AI agents to company data across SharePoint, databases, and documents is complex. Foundry IQ + Fabric IQ provide secure, unified access through one API. Learn to connect agents to multiple sources, configure permissions, use Agent Factory for deployment, and ensure agents understand business context, not just raw data.", "u": "https://fabriccon.com/program/agenda?session=1081123", "tags": ["Power BI", "Microsoft Foundry", "Fabric IQ"]}, {"t": "Taking Direct Lake to the Next Level", "d": "2026-03-20", "s": "10:10 AM", "e": "11:10 AM", "tr": "Power BI, Data Engineering", "ty": "Session", "l": "300", "sp": ["Philip Seamark", "Christian Wade"], "desc": "See what's new for Direct Lake semantic modeling, then dive into the technical details that matter most for enterprise scale. Learn how cardinality, monitoring, and V‑Order influence performance, with practical demos and guidance you can apply straight away.", "u": "https://fabriccon.com/program/agenda?session=1074659", "tags": ["Power BI", "Data Engineering"]}, {"t": "Unifying Data Discovery: A Real-World Implementation of Microsoft Purview Unified Catalog", "d": "2026-03-20", "s": "10:10 AM", "e": "11:10 AM", "tr": "Microsoft Purview", "ty": "Session", "l": "200", "sp": ["Anna Gebler"], "desc": "In a data-driven world, managing data assets effectively is vital. This session highlights Lufthansa Group’s successful adoption of Microsoft Purview Unified Catalog as its central data catalog. Attendees will learn key architectural decisions, best practices, challenges faced, and lessons learned.", "u": "https://fabriccon.com/program/agenda?session=1042562", "tags": ["Microsoft Purview"]}, {"t": "Simplify management of hybrid and multi-cloud SQL Server using Azure Arc", "d": "2026-03-20", "s": "10:10 AM", "e": "11:10 AM", "tr": "Azure SQL, SQLCON, SQL Server", "ty": "Session", "l": "200", "sp": ["Lance Wright", "Anitha Adusumilli"], "desc": "Managing SQL Server in hybrid and multi-cloud environments can be challenging. Azure Arc streamlines SQL Server operations across on-prem, edge, and even other public clouds. Discover how to use built-in capabilities like best practices assessment, performance monitoring, and migration tools to centralize insights, simplify daily operations, and get ready for migration to Azure.", "u": "https://fabriccon.com/program/agenda?session=1089974", "tags": ["SQLCON", "Azure SQL", "SQL Server"]}, {"t": "The Fabric Access Puzzle: Cracking Permission Problems with Confidence", "d": "2026-03-20", "s": "10:10 AM", "e": "11:10 AM", "tr": "Admin & Governance", "ty": "Session", "l": "300", "sp": ["Pragati Jain"], "desc": "Permissions got you puzzled? Discover how to crack common access problems, streamline permissions and implement best practices for a secure, well-managed and collaboration-ready Fabric environment; because permissions can make or break your Fabric setup.", "u": "https://fabriccon.com/program/agenda?session=1062517", "tags": ["Admin & Governance"]}, {"t": "Microsoft Fabric Essentials: No-Code to Pro-Code with Dataflows Gen2", "d": "2026-03-20", "s": "10:10 AM", "e": "11:10 AM", "tr": "Data Engineering, Developer Experiences", "ty": "Session", "l": "300", "sp": ["Eric Overfield"], "desc": "Microsoft Fabric Dataflows Gen2 empowers everyone to prepare data efficiently. In this session, learn no-code steps for quick wins, low-code techniques with Power Query for flexibility, and pro-code customization with M for full control. Discover practical strategies to simplify data prep and enable governed, reusable data at scale.", "u": "https://fabriccon.com/program/agenda?session=1076569", "tags": ["Developer Experiences", "Data Engineering"]}, {"t": "Azure SQL MI Unleashed: Inside the Next‑Gen GP & What’s Coming Next", "d": "2026-03-20", "s": "10:10 AM", "e": "11:10 AM", "tr": "Azure SQL, SQLCON, Azure SQL", "ty": "Session", "l": "300", "sp": ["Vladimir Ivanovic"], "desc": "If you plan to migrate and modernize your SQL workloads in the cloud, Azure SQL Managed Instance (SQL MI) is your best choice - now reimagined for speed, scale, and flexibility. \nIn this session we will deep‑dive into the Next‑Gen SQL MI GP architecture and how it delivers faster performance, greater scalability and smarter resource tuning, making it a great choice for your key database workloads.", "u": "https://fabriccon.com/program/agenda?session=1089844", "tags": ["SQLCON", "Azure SQL"]}, {"t": "Unstoppable Fabric: Capacity Planning, Smart Alerting & Workload Tuning", "d": "2026-03-20", "s": "10:10 AM", "e": "11:10 AM", "tr": "Data Warehousing, Admin & Governance", "ty": "Session", "l": "300", "sp": ["Iurii Iurchenko"], "desc": "Learn how to make Microsoft Fabric unstoppable by combining capacity planning, smart alerting, and workload tuning. We’ll use the Fabric Capacity Metrics app and API to read CU usage and throttling, plan and schedule ETL/Spark/refresh workloads, configure alerts (incl. Data Activator), and apply Spark/Warehouse best practices so Fabric stays fast, predictable, and cost-efficient.", "u": "https://fabriccon.com/program/agenda?session=1079803", "tags": ["Admin & Governance", "Data Warehousing"]}, {"t": "90 Days, 1 Fabric Foundation: Delivering SQL Mirroring at Scale", "d": "2026-03-20", "s": "10:10 AM", "e": "11:10 AM", "tr": "Data Engineering, Data Integration", "ty": "Session", "l": "300", "sp": ["Alex Carvalho", "Rick Weber"], "desc": "In this case study, Caplugs transformed fragile pipelines by shifting architecture—not the business. See how Fabric SQL Mirroring replaced brittle ingestion, cut technical debt, and delivered a stable, low-latency foundation. Learn how unified ERP analytics, governance, and scalable patterns created a sustainable, enterprise-ready Fabric implementation.", "u": "https://fabriccon.com/program/agenda?session=1123243", "tags": ["Data Engineering", "Data Integration"]}, {"t": "The Hidden Strategic Leverage in Modern Data & AI Architectures", "d": "2026-03-20", "s": "10:10 AM", "e": "11:10 AM", "tr": "Real-Time Intelligence, Data Science", "ty": "Session", "l": "200", "sp": ["Vignesh Ganesan"], "desc": "Most enterprises have adopted open data and AI architectures, yet continue to operate as if they are vendor-locked. This session highlights the hidden strategic and financial leverage embedded in modern architectures, showing how centralized governance can coexist with budget control and compute choice. Attendees will learn how to unlock cost efficiency, optionality, and negotiating power without re-platforming or migration.", "u": "https://fabriccon.com/program/agenda?session=1128965", "tags": ["Data Science", "Real-Time Intelligence"]}, {"t": "Reporting with action: Visualizations with translytical task flows in Power BI and Fabric", "d": "2026-03-20", "s": "11:30 AM", "e": "12:30 PM", "tr": "Power BI, SQL in Fabric", "ty": "Session", "l": "200", "sp": ["Zoe Douglas", "Denyse Niwenshuti"], "desc": "Join this session to learn about translytical task flows combining Power BI reports and Fabric user data functions together for actionable reports with a click of a button. We’ll demo how to set it up, the options you have, and specific examples of these reports in action. Interested in what this is or are you already using it today? We’ll have insights you don’t want to miss!", "u": "https://fabriccon.com/program/agenda?session=1075109", "tags": ["Power BI", "SQL in Fabric"]}, {"t": "SQL Performance Supercharged: Strategies for Azure SQL Performance Optimization", "d": "2026-03-20", "s": "11:30 AM", "e": "12:30 PM", "tr": "Azure SQL, SQLCON, SQL in Fabric", "ty": "Session", "l": "300", "sp": ["Naveen Samba", "Mukesh Kumar"], "desc": "Discover how the Azure SQL PG Engineering team tackles complex, mission-critical performance challenges across Azure SQL DB and Managed Instance. Through real customer cases and practical demos, learn sharp diagnostic techniques, hidden optimization opportunities, and the most common pitfalls to avoid when tuning workloads pre- or post-migration.", "u": "https://fabriccon.com/program/agenda?session=1079910", "tags": ["SQLCON", "Azure SQL", "SQL in Fabric"]}, {"t": "Mastering Fabric Data Engineering Admin and Capacity Management", "d": "2026-03-20", "s": "11:30 AM", "e": "12:30 PM", "tr": "Data Engineering, Admin & Governance", "ty": "Session", "l": "400", "sp": ["Santhosh Kumar Ravindran", "Christopher Finlan"], "desc": "Optimize Microsoft Fabric Data Engineering for production. Learn about governance controls for Notebooks, Lakehouses, and Spark Job Definitions. We'll cover administrative roles, capacity management for cost and performance, and scaling best practices.", "u": "https://fabriccon.com/program/agenda?session=1046776", "tags": ["Data Engineering", "Admin & Governance"]}, {"t": "Copilot to the Rescue -Simplifying DBA tasks in SSMS 22", "d": "2026-03-20", "s": "11:30 AM", "e": "12:30 PM", "tr": "SQL Server, SQLCON, Admin & Governance", "ty": "Session", "l": "200", "sp": ["Warwick Rudd", "Kelly Broekstra"], "desc": "Unlock faster, smarter database management with Github Copilot in SSMS 22. This session shows how AI-driven guidance simplifies everyday DBA tasks from faster troubleshooting, writing better T-SQL, boosting productivity and reducing errors. \n\nIn this session you will see practical demos and learn how Github Copilot becomes your essential assistant.", "u": "https://fabriccon.com/program/agenda?session=1079226", "tags": ["SQL Server", "Admin & Governance", "SQLCON"]}, {"t": "Chaos to Clarity: Governance and Adoption Lessons from Rolling Out Power BI and Fabric", "d": "2026-03-20", "s": "11:30 AM", "e": "12:30 PM", "tr": "Admin & Governance, Power BI", "ty": "Session", "l": "300", "sp": ["Chris Aleman"], "desc": "Power BI + Fabric at scale? Chaos looms—fragmented workspaces, messy permissions, frustrated users. Join us to see how we turned disorder into a governance playbook that accelerates adoption. Learn role-based access, streamlined workspace/app strategies, and AI-ready best practices to avoid pitfalls and win enterprise buy-in.", "u": "https://fabriccon.com/program/agenda?session=1034504", "tags": ["Power BI", "Admin & Governance"]}, {"t": "Autonomous Fabric: Agentic Data Quality Using Fabric Data Agents", "d": "2026-03-20", "s": "11:30 AM", "e": "12:30 PM", "tr": "Data Science, Data Integration", "ty": "Session", "l": "200", "sp": ["David Mills"], "desc": "Data Quality issues drain engineering time and weaken business confidence in data platforms.\n\nWhat if Fabric Data Agents could detect DQ issues autonomously, analyse their root cause, and guide engineers directly to a fix? \n\nThis session demonstrates the full architecture with a live demo - capturing DQ signals, triggering agent-led investigations, and integrating agent outputs into ETL pipelines.", "u": "https://fabriccon.com/program/agenda?session=1079380", "tags": ["Data Science", "Data Integration"]}, {"t": "Load Testing Performance for SQL Server", "d": "2026-03-20", "s": "11:30 AM", "e": "12:30 PM", "tr": "SQL Server, SQLCON", "ty": "Session", "l": "300", "sp": ["Anthony Nocentino"], "desc": "Learn the fundamentals of load testing SQL Server - from planning to execution and analysis - to boost performance on-premises or in the cloud. We’ll cover hardware, VM, and I/O stack insights, compare synthetic vs. real workloads, explore tools like DiskSpd, HammerDB, and Workload Tools, and use PowerShell, DMVs, and PerfMon for automated data collection and analysis.", "u": "https://fabriccon.com/program/agenda?session=1080684", "tags": ["SQL Server", "SQLCON"]}, {"t": "Patterns and Best Practice with Fabric CI/CD", "d": "2026-03-20", "s": "11:30 AM", "e": "12:30 PM", "tr": "Data Engineering, Power BI", "ty": "Session", "l": "300", "sp": ["Ted Pattison"], "desc": "This session teaches best practices with Fabric GIT integration to ensure changes to Fabric projects are automatically tested and deployed, leading to faster and more reliable releases. Attendees will learn effective branching strategies for merging changes from feature workspaces into production.", "u": "https://fabriccon.com/program/agenda?session=1068114", "tags": ["Power BI", "Data Engineering"]}, {"t": "Smart Routing: Real-Time Transport Optimization with Fabric", "d": "2026-03-20", "s": "11:30 AM", "e": "12:30 PM", "tr": "Real-Time Intelligence, Data Science", "ty": "Session", "l": "300", "sp": ["Robert Leal", "Manu Huygens"], "desc": "Discover how Microsoft Fabric enables real-time transportation optimization. Learn to ingest GPS data with Eventstream, visualize routes on live maps, and integrate linear optimization models to minimize cost and emissions. Explore how data agents and AI Foundry can help in identifying EV-ready routes based on charging infrastructure.", "u": "https://fabriccon.com/program/agenda?session=1081363", "tags": ["Data Science", "Real-Time Intelligence"]}, {"t": "Modern Data Warehousing in Fabric: Cost, Scale, and Control", "d": "2026-03-20", "s": "11:30 AM", "e": "12:30 PM", "tr": "Data Warehousing", "ty": "Session", "l": "200", "sp": ["Bret Myers", "Sowmya Sivaraman"], "desc": "Want to learn how to get the best performance while keeping control of cost? In this session we'll go into the details of controlling the underlying compute resource with custom sql pools and understanding the impact they have on billing.", "u": "https://fabriccon.com/program/agenda?session=1072196", "tags": ["Data Warehousing"]}, {"t": "SQL in the Fabric Era: Practical Techniques for Modern Data Integration", "d": "2026-03-20", "s": "11:30 AM", "e": "12:30 PM", "tr": "SQL in Fabric, SQLCON", "ty": "Session", "l": "200", "sp": ["Kevin Pereira"], "desc": "SQL pros, meet Fabric! This session shares hands-on examples of SQL database in Fabric in action with analytics, governance, and Power BI integration included. Discover how to extend your SQL skills into a modern data ecosystem without leaving your comfort zone.", "u": "https://fabriccon.com/program/agenda?session=1079969", "tags": ["SQLCON", "SQL in Fabric"]}, {"t": "Empowering Lakehouse Solutions with Fabric Warehouse", "d": "2026-03-20", "s": "11:30 AM", "e": "12:30 PM", "tr": "Data Warehousing, Data Engineering", "ty": "Session", "l": "300", "sp": ["Christian Henrik Reich"], "desc": "Microsoft Fabric Lakehouses get lots of attention, yet the Warehouse’s evolution and true potential in a lakehouse solution are often overlooked.\n\nThis session covers:\n* Engine deep dive\n* Performance\n* Warehouse’s role in lakehouse solutions\n* Interoperability with Spark and lakehouses\n\nAttendees will see how the Warehouse has evolved and how to apply it effectively in a lakehouse solution.", "u": "https://fabriccon.com/program/agenda?session=1080692", "tags": ["Data Engineering", "Data Warehousing"]}, {"t": "From Legacy BI to Insight at Speed: How PGIM Rebuilt Analytics with Microsoft Fabric and Power BI", "d": "2026-03-20", "s": "11:30 AM", "e": "12:30 PM", "tr": "Power BI", "ty": "Session", "l": "300", "sp": ["Pranay Desai", "Eric Kopchinski"], "desc": "When analytics can’t answer “what’s happening right now?” without manual effort, organizations lose time and momentum. PGIM modernized its fragmented BI environment into a unified analytics platform on Microsoft Fabric to deliver real-time insight and scale AI. By unifying data ingestion, modeling, and reporting—and integrating Snowflake data—PGIM built a governed, high-performance foundation for self-service analytics. Power BI reporting with Exploration View replaced legacy Cognos logic, streamlined pipelines, and reduced technical debt. Copilot now accelerates development and AI-assisted discovery. This session covers the architecture, design decisions, and lessons learned.", "u": "https://fabriccon.com/program/agenda?session=1145001", "tags": ["Power BI"]}, {"t": "DEI Lunch Session: Adversity Leadership - Leading with Clarity in High-Pressure Environments", "d": "2026-03-20", "s": "12:30 PM", "e": "01:45 PM", "tr": "Diversity, Equity & Inclusion", "ty": "Special Event", "l": "100", "sp": ["Michael Allison"], "desc": "Modern IT teams operate under constant pressure—governance demands, rapid change, rising burnout, and high-stakes decision-making. Teams from all backgrounds, across the spectrum must work together to achieve goals. \nAttendees will learn to work together to convert pressure into precision, lead with confidence when it matters most, and build resilient, high-performing environments where people can thrive.", "u": "https://fabriccon.com/program/agenda?session=1079624", "tags": ["Diversity", "Equity & Inclusion"]}, {"t": "Linking Enterprise Data Estates to Fabric for OneLake & AI: A Real-World Case Study Featuring Fiserv", "d": "2026-03-20", "s": "01:00 PM", "e": "01:20 PM", "tr": "OneLake, Admin & Governance", "ty": "Session", "l": "200", "sp": ["Jake Bengtson", "Ishan Adhikari"], "desc": "A key challenge in getting your data estate ready for using Fabric's unified capabilities is eliminating data silos and complexity. That requires implementing novel design patterns for connecting, capturing, transforming, and delivering data pipelines from existing applications and legacy platforms into Fabric for modernizing your data estate. \n\nWe will walk through the architecture used to capture and stream change data from production financial systems, apply transformations and validation in-flight, and deliver trusted, real-time data into Fabric to support operational analytics, AI workloads, and agent-based applications.", "u": "https://fabriccon.com/program/agenda?session=1131879", "tags": ["Admin & Governance", "OneLake"]}, {"t": "The Hybrid Data Future: When to Persist, When to Let Agents Fetch", "d": "2026-03-20", "s": "01:00 PM", "e": "01:20 PM", "tr": "Data Engineering, OneLake", "ty": "Session", "l": "100", "sp": ["Partha Mishra"], "desc": "The \"persist everything\" era of data architecture is ending. Microsoft Fabric is the first platform that lets organizations make a genuine choice: persist strategically in OneLake, access external data via shortcuts and mirroring, or let AI agents retrieve directly from source systems at runtime - all under one security and governance model. This session explores the decision framework: when does persistence remain critical, and when can agents reason on-demand? Learn how the semantic layer - the Fabric IQ that grounds agents in trusted business data - becomes the governance backbone for agentic queries, and how leading organizations are compressing implementation timelines from months to weeks - shifting from project delivery to efficient, repeatable, scalable outcomes.", "u": "https://fabriccon.com/program/agenda?session=1135928", "tags": ["Data Engineering", "OneLake"]}, {"t": "Data Modeling Like a Pro in Fabric", "d": "2026-03-20", "s": "02:00 PM", "e": "03:00 PM", "tr": "Power BI, Developer Experiences", "ty": "Session", "l": "200", "sp": ["Christian Wade", "Rui Romano"], "desc": "Join the Fabric product team for an in-depth session to learn about data modeling in Fabric, including Direct Lake and composite models for scale and flexibility, and AI-first workflows to achieve 10x productivity. Get ready for mind-blowing demos and sneak peaks into upcoming capabilities so you can develop semantic models like the experts.", "u": "https://fabriccon.com/program/agenda?session=1083906", "tags": ["Power BI", "Developer Experiences"]}, {"t": "Forget Prompts: Building Declarative AI Pipelines in Fabric", "d": "2026-03-20", "s": "02:00 PM", "e": "03:00 PM", "tr": "Data Science, Data Engineering", "ty": "Session", "l": "200", "sp": ["Sandeep Pawar"], "desc": "Prompt engineering is powerful but brittle. Hard to scale, harder to maintain. Learn how to build declarative AI pipelines in Microsoft Fabric to tame unstructured data and unlock insights. Discover pitfalls, tools, and techniques to optimize and deliver successful solutions", "u": "https://fabriccon.com/program/agenda?session=1066701", "tags": ["Data Science", "Data Engineering"]}, {"t": "When AI meets your database: Securing sensitive data in Azure SQL in an AI-driven world", "d": "2026-03-20", "s": "02:00 PM", "e": "03:00 PM", "tr": "Azure SQL, SQLCON, Azure SQL", "ty": "Session", "l": "200", "sp": ["Shoham Dasgupta"], "desc": "As AI becomes embedded in every application, protecting sensitive data in Azure SQL is vital. This session explores how to secure sensitive data from AI agents and design a defense-in-depth model using Azure SQL's existing security stack - modern authentication, granular access control, data protection, monitoring, auditing, and more. Learn how to confidently use Azure SQL to power AI applications.", "u": "https://fabriccon.com/program/agenda?session=1083498", "tags": ["SQLCON", "Azure SQL"]}, {"t": "Fabric AI-powered automation for pro-developers: what’s new and what’s next", "d": "2026-03-20", "s": "02:00 PM", "e": "03:00 PM", "tr": "Developer Experiences", "ty": "Session", "l": "200", "sp": ["Holly Kelly"], "desc": "A fast-paced tour of what’s new and what’s coming next for automation in Microsoft Fabric including some exciting new announcements. We’ll share updates on the Fabric CLI, Fabric MCP Servers, Terraform provider, SDKs and more, plus end-to-end demos for CI/CD, IaC, and pro-dev workflows. Come ask questions and share feedback directly with the team building Fabric’s automation and pro-dev experiences.", "u": "https://fabriccon.com/program/agenda?session=1081048", "tags": ["Developer Experiences"]}, {"t": "Semantic Link Labs: The Data Detective’s Toolkit", "d": "2026-03-20", "s": "02:00 PM", "e": "03:00 PM", "tr": "Power BI, Data Engineering", "ty": "Session", "l": "300", "sp": ["Jason Romans"], "desc": "Every data detective needs the right toolkit—and Semantic Link Labs delivers. In this demo-heavy session, you’ll see it link Power BI datasets with Python notebooks for deeper diagnostics. Learn to trace relationships, uncover hidden dependencies, validate measures, and resolve issues that impact report quality, performance, and reliability. Get patterns for monitoring, validating, and correcting.", "u": "https://fabriccon.com/program/agenda?session=1074606", "tags": ["Power BI", "Data Engineering"]}, {"t": "Build Smarter Analytics Assistants with Fabric Data Agents and Copilot Studio", "d": "2026-03-20", "s": "02:00 PM", "e": "03:00 PM", "tr": "Data Science, Power BI", "ty": "Session", "l": "300", "sp": ["Piotr Prussak"], "desc": "Learn how to connect Microsoft Fabric data agents with Copilot Studio to deliver intelligent, conversational analytics. This session covers modeling best practices, schema design, grounded responses, testing patterns, and decision guides for choosing when and how to expose semantic models and data agents to copilots.", "u": "https://fabriccon.com/program/agenda?session=1081577", "tags": ["Data Science", "Power BI"]}, {"t": "Securing all of your OneLake data", "d": "2026-03-20", "s": "02:00 PM", "e": "03:00 PM", "tr": "Admin & Governance, Data Dev", "ty": "Session", "l": "200", "sp": ["Ginger Grant"], "desc": "Fabric includes multiple layers of security across OneLake. This session breaks down RBAC, sharing permissions, shortcut behaviors, Semantic model Row Level Security and OneLake security and shows how they interact in real-world architectures. Learn how to design secure, least-privilege data access in Fabric throughout your data estate and more importantly the steps you need to employ to test it.", "u": "https://fabriccon.com/program/agenda?session=1081511", "tags": ["Admin & Governance", "Data Dev"]}, {"t": "Unlock the Azure SQL Advantage with a streamlined migration experience via Azure Arc and AI", "d": "2026-03-20", "s": "02:00 PM", "e": "03:00 PM", "tr": "SQL Server, SQLCON, Azure SQL", "ty": "Session", "l": "400", "sp": ["Sudhir Kumar Raparla", "Anitha Adusumilli"], "desc": "Learn how Azure SQL gives you best price/performance with Azure benefits, flexible SKU configurations and how seamless SQL migration experience in Azure Arc puts you on fast-track migration journey to Azure SQL with evergreen assessments, best fit SKU recommendations and near zero‑downtime migrations. Learn how SSMA accelerates Oracle/Sybase to Azure SQL migrations with AI Code Conversion Copilot.", "u": "https://fabriccon.com/program/agenda?session=1089941", "tags": ["SQL Server", "Azure SQL", "SQLCON"]}, {"t": "My Favorite New T-SQL in SQL Server 2025", "d": "2026-03-20", "s": "02:00 PM", "e": "03:00 PM", "tr": "SQL Server, SQLCON, Data Engineering", "ty": "Session", "l": "300", "sp": ["Edward Pollack"], "desc": "This session is a dive into everything new that appears in SQL Server 2025 and are already available in Azure SQL Database.\n\nLooking to use the new Regex functions? There is a surprising upgrade snuck in there for STRING_SPLIT().\n\nIs PRODUCT() really useful? Yes. Yes it is!\n\nWhat is fuzzy string matching all about?\n\nJSON support is finally here!\n\nThere's more to be had, waiting for you right here!", "u": "https://fabriccon.com/program/agenda?session=1074834", "tags": ["SQL Server", "Data Engineering", "SQLCON"]}, {"t": "If You’re Not Using Open Mirroring Yet, You’re Doing It the Hard Way", "d": "2026-03-20", "s": "02:00 PM", "e": "03:00 PM", "tr": "Data Integration, Developer Experiences", "ty": "Session", "l": "300", "sp": ["Jon Christian Halvorsen"], "desc": "Still landing data the old way? You’re paying too much for it.\n\nOpen Mirroring in Microsoft Fabric is faster, simpler and free as in free beer.\n\nIn this deep-dive, learn how to build and tune open-mirroring pipelines with Python, measure real-world performance, and see why this cost-free pattern should be your default for data landing.", "u": "https://fabriccon.com/program/agenda?session=1074803", "tags": ["Developer Experiences", "Data Integration"]}, {"t": "Beyond Monitoring: AI-Driven Spark Optimization in Microsoft Fabric", "d": "2026-03-20", "s": "02:00 PM", "e": "03:00 PM", "tr": "Data Engineering, Data Science", "ty": "Session", "l": "200", "sp": ["Anu Venkataraman", "Virginia Roman"], "desc": "Join this demo by Microsoft AI and Spark experts to see how Fabric takes Spark observability to the next level! Learn how to stream Spark logs to Eventhouse using Diagnostic Emitter. See Fabric AI/ML tooling in action to detect bottlenecks, predict resource impact, and suggest code improvements to optimize performance and cost. Visualize the insights and recommendations in Real Time Dashboard.", "u": "https://fabriccon.com/program/agenda?session=1087887", "tags": ["Data Science", "Data Engineering"]}, {"t": "Herding Fabric Cats: Administration and Governance Guidance", "d": "2026-03-20", "s": "02:00 PM", "e": "03:00 PM", "tr": "Admin & Governance, OneLake", "ty": "Session", "l": "300", "sp": ["Jerid Fortney", "John Miner"], "desc": "Fabric governance is challenging: users create workspaces fast, data sprawls, and costs spike. This session will help you \"herd the cats\" using Microsoft's tools.\n\nYou will leave with a practical, battle-tested governance framework and real-world strategies. (No actual cats were harmed.)", "u": "https://fabriccon.com/program/agenda?session=1081460", "tags": ["Admin & Governance", "OneLake"]}, {"t": "Real Time Reporting with D365 Data Events and Fabric", "d": "2026-03-20", "s": "02:00 PM", "e": "03:00 PM", "tr": "Real-Time Intelligence, Data Engineering", "ty": "Session", "l": "300", "sp": ["Tobias Eld"], "desc": "In this session, we will explore how Dynamics 365 Data Events enables the generation of event messages triggered by CRUD operations on data entities. These messages can be streamed to Azure Event Hubs, consumed by a Fabric Event Stream, and ultimately fed into an Eventhouse that serves as the data source for live Power BI reports. \n\nWe will dive into several practical use cases for real-time reporting, then guide you through the setup and configuration process for this powerful solution.  \n\nThis session provides a technical deep dive into the integration of Dynamics 365, Azure, and Fabric, covering key components, architectural best practices, and real-world considerations.", "u": "https://fabriccon.com/program/agenda?session=1129374", "tags": ["Data Engineering", "Real-Time Intelligence"]}, {"t": "Delivering Insights Where Your Users Work", "d": "2026-03-20", "s": "03:15 PM", "e": "04:15 PM", "tr": "Power BI, Power BI", "ty": "Session", "l": "200", "sp": ["Dustin Askins", "Anita Ambalavanan"], "desc": "Learn practical strategies for sharing Power BI content across your company. We’ll cover distributing insights through apps (including organizational apps), and how business users can access Power BI directly from their M365 tools and Copilot to boost productivity and make informed decisions. You’ll  get a deep look at current capabilities as well as what’s coming next.", "u": "https://fabriccon.com/program/agenda?session=1083357", "tags": ["Power BI"]}, {"t": "Automate at Scale with Event-Driven Architectures and Business Events", "d": "2026-03-20", "s": "03:15 PM", "e": "04:15 PM", "tr": "Real-Time Intelligence", "ty": "Session", "l": "300", "sp": ["Roberto Cervantes", "Ajeta Singhal"], "desc": "Disconnected systems and manual processes slow your business response time. Event-driven architectures solve this by enabling real-time responsiveness across your organization. Discover how Activator orchestrates event flows and integrates diverse sources, while Business Events provide instant visibility and trigger automated workflows. Learn to configure event-driven pipelines, set up Business Events for monitoring, and enable AI-driven decisions at scale.", "u": "https://fabriccon.com/program/agenda?session=1065937", "tags": ["Real-Time Intelligence"]}, {"t": "Building modern data architectures with Microsoft Fabric", "d": "2026-03-20", "s": "03:15 PM", "e": "04:15 PM", "tr": "Data Warehousing", "ty": "Session", "l": "100", "sp": ["James Serra"], "desc": "Learn how Microsoft Fabric can be leveraged with the architectures: Data fabric, data lakehouse, and data mesh.  Get a tour of each architecture and explore their pros and cons. By the end of the session, you’ll have a clear understanding of how to use Microsoft Fabric to build and optimize these diverse data architectures.", "u": "https://fabriccon.com/program/agenda?session=1019088", "tags": ["Data Warehousing"]}, {"t": "SQL Server 2025 for DBAs", "d": "2026-03-20", "s": "03:15 PM", "e": "04:15 PM", "tr": "SQL Server, SQLCON", "ty": "Session", "l": "200", "sp": ["Marcelo Adade", "Roberto Fonseca"], "desc": "Explore the key advancements in SQL Server 2025 that matter most for DBAs. We’ll highlight improvements in performance, availability, and administration, including faster queries, better indexing, enhanced HA, and new management tools. Learn how these features reduce downtime, boost efficiency, and help you get the most from SQL Server 2025.", "u": "https://fabriccon.com/program/agenda?session=1079484", "tags": ["SQL Server", "SQLCON"]}, {"t": "Fabric Sprawl - Techniques to Optimize Your Fabric Capacity", "d": "2026-03-20", "s": "03:15 PM", "e": "04:15 PM", "tr": "Admin & Governance, Developer Experiences", "ty": "Session", "l": "300", "sp": ["Curtis Stallings", "Marcus Radue"], "desc": "Learn how to address a sprawling Fabric environment with ungoverned items across multiple workspaces and capacities. Extend FUAM to gain valuable insights that drive decision-making and backlog prioritization. Design the right balance between autonomy and security in your Fabric environment to deliver an optimal experience for both end users and developers.", "u": "https://fabriccon.com/program/agenda?session=1079749", "tags": ["Developer Experiences", "Admin & Governance"]}, {"t": "Demystifying Spark Profile Optimizations in Microsoft Fabric", "d": "2026-03-20", "s": "03:15 PM", "e": "04:15 PM", "tr": "Data Engineering", "ty": "Session", "l": "400", "sp": ["Thibauld Croonenborghs"], "desc": "Optimizing Spark workloads in Microsoft Fabric can be a complex endeavor, given the array of available configurations and techniques. Terms like V-Order, Z-Order, and considerations for read-heavy versus write-heavy profiles often add to the confusion. In this session, we'll bring clarity to these concepts, offering a structured overview of each optimization strategy.​", "u": "https://fabriccon.com/program/agenda?session=1076404", "tags": ["Data Engineering"]}, {"t": "Building MLOps for Traditional ML in Microsoft Fabric", "d": "2026-03-20", "s": "03:15 PM", "e": "04:15 PM", "tr": "Data Science", "ty": "Session", "l": "300", "sp": ["Nicholas Leonhard"], "desc": "Discover how Microsoft Fabric enables a modern Machine Learning Operation for Traditional ML. Attendees will observe a practical approach to building ML pipelines using Notebooks, Lakehouses, Pipelines, Environments, and Experiments. We'll also explore custom spark pools, data manipulation tools, and machine learning libraries.", "u": "https://fabriccon.com/program/agenda?session=1079078", "tags": ["Data Science"]}, {"t": "Vibe Coding a Power BI Embedded Portal - From Zero to Hero in 60 Minutes", "d": "2026-03-20", "s": "03:15 PM", "e": "04:15 PM", "tr": "Power BI, Developer Experiences", "ty": "Session", "l": "200", "sp": ["Peer Grønnerup"], "desc": "Power BI Embedded isn’t just for developers. \n\nIn this fast-paced vibe-coding session, we’ll demystify it by building a real custom portal in 60 minutes, using AI to speed things up. \n\nSee how to set Power BI Embedded up quickly, craft a user-centric experience, improve navigation beyond the service, and unlock powerful opportunities without heavy coding, giving you a fresh view of what’s truly possible.", "u": "https://fabriccon.com/program/agenda?session=1080837", "tags": ["Power BI", "Developer Experiences"]}, {"t": "Batteries included: SQL DevOps with SQL projects", "d": "2026-03-20", "s": "03:15 PM", "e": "04:15 PM", "tr": "SQL Server, SQLCON, SQL Server", "ty": "Session", "l": "200", "sp": ["Drew Skwiers-Koballa"], "desc": "The evolution of SQL projects continues with expanded IDE support and deeper integration in the Fabric platform. Using the latest in VS Code and SSMS, we’ll walk through keeping our database in source control, integrating changes made in another database, and evaluating deployment plans. Finally, we'll automate CI/CD processes with REST APIs for SQL database in Fabric and the SqlPackage CLI.", "u": "https://fabriccon.com/program/agenda?session=1089929", "tags": ["SQL Server", "SQLCON"]}, {"t": "Architecting Zero ETL: Real-Time Analytics from Azure Database for PostgreSQL using Fabric Mirroring", "d": "2026-03-20", "s": "03:15 PM", "e": "04:15 PM", "tr": "PostgreSQL, Data Integration", "ty": "Session", "l": "300", "sp": ["Paula Berenguel", "Guy Bowerman"], "desc": "What is new with Azure Database for PostgreSQL Mirroring in Fabric? Explore the latest enhancements that simplify data movement and integration. We’ll take a deep dive into the zero-copy, live replication architecture—showing how PostgreSQL data flows seamlessly into OneLake without ETL. Plus, see it in action with a live demo!", "u": "https://fabriccon.com/program/agenda?session=1062767", "tags": ["PostgreSQL", "Data Integration"]}, {"t": "Transforming Industrial Operations with Real-time Intelligence and Agentic AI", "d": "2026-03-20", "s": "03:15 PM", "e": "04:15 PM", "tr": "Real-Time Intelligence, OneLake", "ty": "Session", "l": "300", "sp": ["Yasaswi Akkaraju", "Stuti Singh"], "desc": "Microsoft Fabric Real-Time Intelligence transforms industrial operations through Real-Time Dashboard, Data Activator, agentic AI, and ART enablement. Organizations shift from reactive firefighting to autonomous, predictive operations—monitoring equipment health, triggering intelligent workflows, and orchestrating maintenance responses at streaming velocity.", "u": "https://fabriccon.com/program/agenda?session=1081139", "tags": ["Real-Time Intelligence", "OneLake"]}];
